INSERT INTO `movies` (`id`, `title`, `description`, `poster_path`, `release_date`, `price`, `created_at`, `updated_at`, `category`) VALUES
(1132, 'LEGO Marvel Avengers: Mission Demolition', 'A young, aspiring hero and superhero fan inadvertently unleashes a powerful new villain looking to rid the world of the Avengers.', 'https://image.tmdb.org/t/p/w500/4KfgyzCgJeG0XJDbqNztdP730Pv.jpg', '2024-10-17', 13.55, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Animation'),
(1133, 'The Avengers', 'British Ministry agent John Steed, under direction from \"Mother\", investigates a diabolical plot by arch-villain Sir August de Wynter to rule the world with his weather control machine. Steed investigates the beautiful Doctor Mrs. Emma Peel, the only suspect, but simultaneously falls for her and joins forces with her to combat Sir August.', 'https://image.tmdb.org/t/p/w500/1p5thyQ4pCy876HpdvFARqJ62N9.jpg', '1998-08-13', 13.74, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1134, 'Crippled Avengers', 'A group of martial artists seek revenge after being crippled by Tu Tin-To, a martial arts master, and his son.', 'https://image.tmdb.org/t/p/w500/eKdvNCKtiuUFvwCXtpwISw8jqZ5.jpg', '1978-12-21', 10.80, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1135, 'Avengers Confidential: Black Widow & Punisher', 'When the Punisher takes out a black-market weapons dealer, he stumbles upon a far-reaching terrorist plot devised by a group known as Leviathan.', 'https://image.tmdb.org/t/p/w500/wJcyYVRPZDOZOD2w0r2R6wuZqqN.jpg', '2014-04-19', 13.95, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Animation'),
(1136, 'LEGO Marvel Avengers: Code Red', 'The Avengers gather to celebrate their latest victory, but their celebration is quickly interrupted by the mysterious disappearance of Black Widow\'s father, Red Guardian. As the Avengers investigate, they discover that Red Guardian isn\'t the only one missing when they meet a dangerous new foe quite unlike anything they\'ve ever encountered before.', 'https://image.tmdb.org/t/p/w500/rDzig50dj7VpLwJ7SThbamETK1G.jpg', '2023-10-26', 15.40, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Animation'),
(1137, 'Avengers: Endgame', 'After the devastating events of Avengers: Infinity War, the universe is in ruins due to the efforts of the Mad Titan, Thanos. With the help of remaining allies, the Avengers must assemble once more in order to undo Thanos\' actions and restore order to the universe once and for all, no matter what consequences may be in store.', 'https://image.tmdb.org/t/p/w500/ulzhLuWrPK07P1YkdWQLZnQh1JL.jpg', '2019-04-24', 13.39, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Adventure'),
(1138, 'Avengers: Age of Ultron', 'When Tony Stark tries to jumpstart a dormant peacekeeping program, things go awry and Earthâ€™s Mightiest Heroes are put to the ultimate test as the fate of the planet hangs in the balance. As the villainous Ultron emerges, it is up to The Avengers to stop him from enacting his terrible plans, and soon uneasy alliances and unexpected action pave the way for an epic and unique global adventure.', 'https://image.tmdb.org/t/p/w500/4ssDuvEDkSArWEdyBl2X5EHvYKU.jpg', '2015-04-22', 11.70, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1140, 'Masked Avengers', 'Philip Kwok plays a repentant killer who vows to destroy the masked gang of which he was a member. A young fighter and his martial arts brothers come to the town to catch the killers, but one of them is not to be trusted!', 'https://image.tmdb.org/t/p/w500/vr54E7RjvMLE4rFgb1NPgZdnpj6.jpg', '1981-05-15', 16.62, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1141, 'Ultimate Avengers 2', 'Mysterious Wakanda lies in the darkest heart of Africa, unknown to most of the world. An isolated land hidden behind closed borders, fiercely protected by its young king: Black Panther. But when brutal alien invaders attack, the threat leaves Black Panther with no option but to go against the sacred decrees of his people and ask for help from outsiders.', 'https://image.tmdb.org/t/p/w500/2bfVNvLKWaxFh1LiOKlvxgiHOXn.jpg', '2006-08-08', 12.71, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Adventure'),
(1142, 'Bikini Avengers', 'When the Jade Empress steals the world\'s largest diamonds, super heroes Bikini Avenger and Thong Girl must stop her before she uses the gems to build a dangerous sci-fi weapon.', 'https://image.tmdb.org/t/p/w500/ehTYWuPKwl8sXPX0I6LnvJUDaVl.jpg', '2015-02-24', 12.45, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Comedy'),
(1143, 'Avengers: Doomsday', 'The Avengers, Wakandans, Fantastic Four, Thunderbolts, and X-Men all fight against Doctor Doom. Plot TBA.', 'https://image.tmdb.org/t/p/w500/6eB2oh1SplddsZYCdayrIdrIGLd.jpg', '2026-04-29', 12.68, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Science Fiction'),
(1144, 'Next Avengers: Heroes of Tomorrow', 'The children of the Avengers hone their powers and go head to head with the very enemy responsible for their parents\' demise.', 'https://image.tmdb.org/t/p/w500/1y4J9HZJoTIMdt77wCq80uXaQJ.jpg', '2008-09-02', 14.14, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Animation'),
(1145, '3 Avengers', 'Ursus and his sword-wielding companions run head-on against a usurper of a throne.', 'https://image.tmdb.org/t/p/w500/skGMVZ41KWezqKa29g8bqpXfLlV.jpg', '1964-11-26', 7.92, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1146, 'Avengers: Secret Wars', 'An upcoming film in Phase 6 of the Marvel Cinematic Universe (MCU) and the finale of The Multiverse Saga. Plot TBA.', 'https://image.tmdb.org/t/p/w500/f0YBuh4hyiAheXhh4JnJWoKi9g5.jpg', '2027-05-05', 18.40, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Science Fiction'),
(1147, 'Avengers from Hell', 'Three macabre short stories about gambling, vengeance and homicide.', 'https://image.tmdb.org/t/p/w500/AuhPoFUKgYBRNDYjsTOPHE56Nzz.jpg', '1981-04-02', 14.94, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Fantasy'),
(1148, 'Avengers Grimm', 'When Rumpelstiltskin destroys the Magic Mirror and escapes to the modern world, the four princesses of \"Once Upon a Time\"-Cinderella, Sleeping Beauty, Snow White, and Rapunzel-are sucked through the portal too. Well-trained and endowed with magical powers, the four women must fight Rumpelstiltskin and his army of thralls before he enslaves everyone on Earth.', 'https://image.tmdb.org/t/p/w500/9sdAHQxt53W8gZKivX0Pdk4DuXA.jpg', '2015-03-17', 15.20, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1149, 'People\'s Avengers', 'About the partisan movement during the Great Patriotic War.', 'https://image.tmdb.org/t/p/w500/D1QpslQSEZ9iCiBr6B5oZsIhOR.jpg', '1943-11-14', 15.10, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Documentary'),
(1150, 'The New Adventures of the Elusive Avengers', 'The action takes place in 1920 during the Civil War.  Crimea on the eve of complete liberation from the White Guards. Returning from patrol, the four brave â€œelusiveâ€ knocked down an airplane. In the field bag of the captured pilot, they find a secret report, which speaks of the existence of defensive fortifications around the coastal city, which the Reds have yet to take. Young heroes get the task to get a map of fortifications and go to the city...', 'https://image.tmdb.org/t/p/w500/pulCmFhk5GkeoV9a6nVg46lo1a3.jpg', '1968-11-04', 9.28, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1151, 'The Avenging Eagle', 'Eagle Chief Yoh Xi-hung raises orphans to be his personal killers. One such is Chik Ming-sing who now wants to put his killer life behind him. When the Eagle Clan come after him, a stranger called Cheuk comes to his assistance It turns out that Cheuk is the son of a family who were robbed and murdered by the Eagles. Now they will team up to destroy the evil clan.', 'https://image.tmdb.org/t/p/w500/tpOVfLNNmWQFNJrfrAnLmdsx8pT.jpg', '1978-09-13', 7.29, '2025-04-14 20:30:18', '2025-04-14 20:30:38', 'Action'),
(1172, 'Romance', 'Bearing similarities to instant messaging as well as Arthurian Romances, Romance is an investigation into language, the durational aesthetics of the structuralist film, and the fluid boundary between participation and spectatorship.', 'https://image.tmdb.org/t/p/w500/lc0Y87ENhG7NZkDIxEPgx9yWmIe.jpg', '2003-01-01', 18.23, '2025-04-14 20:30:51', '2025-04-14 20:30:51', 'Documentary'),
(1190, 'Romance of the West Chamber', 'Cheung, a 23-year-old unmarried travelling scholar, stops by the monastery, where he sees a beautiful woman. Against the rules, Monk Faben allows Cheung to stay and woo the girl, Ann-Ann. She is shy, and also the Prime Minister\'s daughter, so the wooing is arranged by Ann-Ann\'s maid Hung.', 'https://image.tmdb.org/t/p/w500/bup7TBYfLzFjH7r1cLX6iXQS7M0.jpg', '1997-10-09', 12.19, '2025-04-14 20:30:51', '2025-04-14 20:30:51', 'History'),
(1192, 'The Fault in Our Stars', 'Despite the tumor-shrinking medical miracle that has bought her a few years, Hazel has never been anything but terminal, her final chapter inscribed upon diagnosis. But when a patient named Augustus Waters suddenly appears at Cancer Kid Support Group, Hazel\'s story is about to be completely rewritten.', 'https://image.tmdb.org/t/p/w500/ep7dF4QR4Mm39LI958V0XbwE0hK.jpg', '2014-05-16', 13.47, '2025-04-14 20:31:03', '2025-04-14 20:31:03', 'Romance'),
(1193, 'Lollos 6: Lalaland!', '', 'https://image.tmdb.org/t/p/w500/bI6TlKrBMQw5XGli1lzQF3Dalgq.jpg', '2014-06-01', 19.31, '2025-04-14 20:31:11', '2025-04-14 20:31:11', 'Family'),
(1194, 'La La Land', 'What happens when a dim-witted New York Italian guy moves to Hollywood seeking fame and fortune? LA LA Land is the story of relentless Mikey Forearms, and his partner in stupidity Johnny, as they chase the dream and stumble their way through Hollywood\'s back doors. Armed with confidence if not talent, Mikey is anxious to get his career underway. Mikey unleashes himself on casting directors, but none of them appreciate his \"acting chops\". In the pilot episode he is offered a job that is not exactly what he had in mind. Following Johnny\'s suggestion, he meets Super Agent Jerry Flaxman and Big Shot Producer Alan Gilstein. Flaxman and Gilstein think they\'ve found the perfect pawn for their game, but maybe Mikey is not as dumb as he looks. Can he get his lucky break in LA LA Land?', 'https://image.tmdb.org/t/p/w500/nmdBXLTDzTaWzxcY32vz8CSpzbQ.jpg', '2008-03-07', 8.93, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Comedy'),
(1196, 'Going Down in La-La Land', 'A fresh face comes to Hollywood to act in movies but only the gay porn studios are eager to provide him with work.', 'https://image.tmdb.org/t/p/w500/tbgH8Fn3DPJzF5E7uxyjLAoPKIT.jpg', '2011-05-01', 16.21, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Drama'),
(1197, 'Las Hurdes, a Land with Soul', 'A modern answer to Luis BuÃ±uel\'s mythical documentary â€œLand Without Breadâ€ (1933) about Las Hurdes, a historically impoverished region of the province of CÃ¡ceres, in Extremadura, Spain, and also a journey of discovery of the soul of this beautiful land and its inhabitants.', 'https://image.tmdb.org/t/p/w500/p2PBUGf7yURzHh4aTWOerRdrioG.jpg', '2015-09-17', 18.61, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Documentary'),
(1198, 'Gary Numan: Android In La La Land', 'The Godfather of electronic music is on a one-way trip to crack America, returning to the studio for the first time in nearly a decade. Android is a celebration of a music-making pioneer and the love story that helped him turn his life around.', 'https://image.tmdb.org/t/p/w500/1ZCglhextcg9Yc3PeFhIqW1hYPE.jpg', '2016-03-14', 11.91, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Documentary'),
(1199, 'El indefinido. La crÃ­tica de La la land', 'In a post-La la land world, a man must decide whether he loves or he hates it', 'https://image.tmdb.org/t/p/w500/oBMbXTSpvVomZsIefDPjyME6f2I.jpg', '2017-02-27', 7.46, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'unknown'),
(1200, 'Notre-Dame-des-Landes, la reconquÃªte', 'Continuation of the film The tarmac is in the meadow with Michel, the peasant historical figure of the fight against the airport, who will not have known in his lifetime the outcome of the fight of his life ... This new film is the story of  a \"reconquest\", that of the lands of Notre-Dame-des-Landes, a land reserve made available by the abandonment of the airport project.  It is the tale of a human and political adventure that pits residents with different visions about the future of their common territory, and tells of their confrontation with the State ...', 'https://image.tmdb.org/t/p/w500/mtGe2QOwLbrihsjpbyMbiR8XRHj.jpg', '2019-09-16', 8.65, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Documentary'),
(1201, 'The Wild Frontier', 'A growing city, where nearly 7,800 people lived, will be destroyed by 50% in February 2016. How will the 4,000 migrants expelled from the South zone reborn from their ashes in the northern zone. Before the state decided to annihilate the entire territory in October 2016 and to disperse its 11,000 inhabitants, to the four corners of France.', 'https://image.tmdb.org/t/p/w500/fOSQDBcO3qzbvIsoF7J32VPQnj0.jpg', '2018-04-11', 11.71, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Documentary'),
(1202, 'El Milagro y el valor de la vida: Landriscina, Favaloro y Menapace', '', 'https://image.tmdb.org/t/p/w500/xHv4fyt79sFddc2GccCRwBKw5dS.jpg', '1997-12-05', 16.91, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'unknown'),
(1203, 'DEMAIN S\'ENTÃŠTE sur la ZAD de Notre Dame des Landes', '', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 8.36, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'unknown'),
(1204, 'The Dead Lands', 'Hongi, a Maori chieftainâ€™s teenage son, must avenge his fatherâ€™s murder in order to bring peace and honour to the souls of his loved ones after his tribe is slaughtered through an act of treachery. Vastly outnumbered by a band of villains led by Wirepa, Hongiâ€™s only hope is to pass through the feared and forbidden â€œDead Landsâ€ and forge an uneasy alliance with a mysterious warrior, a ruthless fighter who has ruled the area for years.', 'https://image.tmdb.org/t/p/w500/wdlRuuA2CtS0KtaVzAikZxVHRIk.jpg', '2014-09-04', 19.14, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Adventure'),
(1205, 'The Promised Land', 'In nineteenth-century ÅÃ³dÅº, Poland, three friends want to make a lot of money by building and investing in a textile factory. An exceptional portrait of rapid industrial expansion is shown through the eyes of one Polish town.', 'https://image.tmdb.org/t/p/w500/pjk8K5MpQJX0XczTC2KOVWNj0lC.jpg', '1975-02-21', 14.53, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Drama'),
(1206, 'Naruto the Movie: Ninja Clash in the Land of Snow', 'Naruto is thrilled when he is sent on a mission to protect his favorite actress, Yukie Fujikaze, on the set of her new movie, The Adventures of Princess Gale. But when the crew ventures out to film in the icy, foreboding Land of Snow, Yukie mysteriously flees! Naruto and his squad set off to find her... unaware that three Snow Ninja lie in wait, with a sinister purpose that will force Yukie to face her hidden past!', 'https://image.tmdb.org/t/p/w500/eUNRUeSNzm8LktH4HRaYiAReB6R.jpg', '2004-08-21', 10.02, '2025-04-14 20:31:20', '2025-04-14 20:34:21', 'Comedy'),
(1207, 'The Landlady', 'A landlady is taunted by neighborhood kids.', 'https://image.tmdb.org/t/p/w500/elfDN8C1UNIH5hIB0eoE9kn6gF6.jpg', '1900-01-01', 16.14, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Comedy'),
(1208, 'Land of Mine', 'In the days following the surrender of Germany in May 1945, a group of young German prisoners of war is handed over to the Danish authorities and subsequently sent to the West Coast, where they are ordered to remove the more than two million mines that the Germans had placed in the sand along the coast. With their bare hands, crawling around in the sand, the boys are forced to perform the dangerous work under the leadership of a Danish sergeant.', 'https://image.tmdb.org/t/p/w500/7TOYH2VDnYbXpBKlrkdQZUSC3Du.jpg', '2015-12-03', 9.56, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'War'),
(1209, 'The New Land', 'A Swedish immigrant family struggles to adapt to their new life on the American frontier during the second half of the 19th century amidst civil war, native uprising and the lure of gold in California.', 'https://image.tmdb.org/t/p/w500/eC9SDdBwCa0FGckc76q1MBxlks9.jpg', '1972-02-26', 14.28, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Drama'),
(1210, 'The Eagle Has Landed', 'When the Nazi high command learns in late 1943 that Winston Churchill will be spending time at a country estate in Norfolk, it hatches an audacious scheme to kidnap the prime minister and spirit him to Germany for enforced negotiations with Hitler.', 'https://image.tmdb.org/t/p/w500/dxLuj7VIv0ZRdvaIB6eY5fApONF.jpg', '1976-12-24', 13.84, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Adventure'),
(1211, 'The Land Before Time III: The Time of the Great Giving', 'When a sudden shortage of water threatens all life in the great valley, The gang of young dinosaur must cooperate with a group of bullies to make a risky journey outside the valley and find the cause.', 'https://image.tmdb.org/t/p/w500/abcJUBDHi6hxibSgm2bxYK1wAZK.jpg', '1995-03-16', 18.29, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Animation'),
(1212, 'The Vets', 'In the heart of Morvan, Nico, the last vet in the area, struggles to save his patients, his clinic, and his family. When Michel, his partner and mentor, announces his retirement, Nico knows that the hard part is yet to come. \"Don\'t worry, I\'ve found the next generation\" Except that ... The next generation is Alexandra, a 24-hour graduate, brilliant, misanthropic, and not at all willing to return to bury herself in the village of her childhood. Will Nico manage to make her stay?', 'https://image.tmdb.org/t/p/w500/w7bS4nnqZArSgkFU96uPIhxNP6v.jpg', '2019-11-04', 12.76, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Comedy'),
(1213, 'The Country Girl', 'An ex-theater actor is given one more chance to star in a musical yet his alcoholism may prevent it from happening.', 'https://image.tmdb.org/t/p/w500/7LdXybdZcTdZo7lkkrFQKf7byZf.jpg', '1954-12-15', 9.27, '2025-04-14 20:31:20', '2025-04-14 20:31:20', 'Drama'),
(1214, 'Spider-Man', 'One minute he\'s Peter Parker the college student, and the next he\'s Spiderman!', 'https://image.tmdb.org/t/p/w500/3HakxkortobYPDd7tRqKWM9PyxQ.jpg', '1990-01-01', 9.51, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'unknown'),
(1217, 'SPIDERMAN', '', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 17.60, '2025-04-14 20:31:29', '2025-04-14 20:31:29', 'unknown'),
(1219, 'Spider-Man!', 'After being bitten by a radioactive spider, Peter Parker uses his new powers to locate and catch the killer of his beloved Uncle Ben.\r First of the three short films made by \"The Trauma Group\" (Naxo Fiol, Chema Ponze, Gabi Tintorer) on the Marvel character between 1993 and 1996. This is the first film made in Spain, shot without more budget than the spent in the costume of the hero (60,000 pesetas of 1993) and shot with a video-8 camera of the time, so the image and the sound, together with the passage of time make the quality of both very poor. Halfway between the experimental, psychotronic cinema and avant-garde cinema, itÂ´s a very extravagant version of the character, softened in the second incursion of the Trauma Group in the character: \"Peter Parker is Spider-Man\" (1996), closer than this to the original comic.', 'https://image.tmdb.org/t/p/w500/lvXFC3xpMdaIqjFMVEfjpSrelPm.jpg', '1993-10-01', 8.54, '2025-04-14 20:31:29', '2025-04-14 20:31:35', 'Action'),
(1220, 'Spider-Man: All Roads Lead to No Way Home', 'JB Smoove and Martin Starr host a celebration of 20 years of \"Spider-Man\" movies, from the Sam Raimi trilogy to Marc Webb\'s movies and the trio from Jon Watts.', 'https://image.tmdb.org/t/p/w500/e2LLmI5wKIrWGAy9Of3yyWu7Szn.jpg', '2022-05-03', 11.84, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Documentary'),
(1221, 'Spider-Man: Into the Spider-Verse', 'Struggling to find his place in the world while juggling school and family, Brooklyn teenager Miles Morales is unexpectedly bitten by a radioactive spider and develops unfathomable powers just like the one and only Spider-Man. While wrestling with the implications of his new abilities, Miles discovers a super collider created by the madman Wilson \"Kingpin\" Fisk, causing others from across the Spider-Verse to be inadvertently transported to his dimension.', 'https://image.tmdb.org/t/p/w500/iiZZdoQBEYBv6id8su7ImL0oCbD.jpg', '2018-12-06', 12.69, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Animation'),
(1222, 'Spider-Man: Across the Spider-Verse', 'After reuniting with Gwen Stacy, Brooklynâ€™s full-time, friendly neighborhood Spider-Man is catapulted across the Multiverse, where he encounters the Spider Society, a team of Spider-People charged with protecting the Multiverseâ€™s very existence. But when the heroes clash on how to handle a new threat, Miles finds himself pitted against the other Spiders and must set out on his own to save those he loves most.', 'https://image.tmdb.org/t/p/w500/8Vt6mWEReuy4Of61Lnj5Xj704m8.jpg', '2023-05-31', 6.23, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Animation'),
(1223, 'Spider-Man: No Way Home', 'Peter Parker is unmasked and no longer able to separate his normal life from the high-stakes of being a super-hero. When he asks for help from Doctor Strange the stakes become even more dangerous, forcing him to discover what it truly means to be Spider-Man.', 'https://image.tmdb.org/t/p/w500/1g0dhYtq4irTY1GPXvft6k4YLjm.jpg', '2021-12-15', 12.78, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1224, 'Superman, Spider-Man or Batman', 'Aron, a 5-year-old boy, sets together with his worried father on a journey at the end of which he wishes, like the superheroes in the comic books, to save his mother suffering from a heart condition.', 'https://image.tmdb.org/t/p/w500/iUp85s5s7eaPbuCUNqOCeJCEVpY.jpg', '2011-06-01', 12.74, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Drama'),
(1225, 'Spider-Man: Homecoming', 'Following the events of Captain America: Civil War, Peter Parker, with the help of his mentor Tony Stark, tries to balance his life as an ordinary high school student in Queens, New York City, with fighting crime as his superhero alter ego Spider-Man as a new threat, the Vulture, emerges.', 'https://image.tmdb.org/t/p/w500/c24sv2weTHPsmDa7jEMN0m2P3RT.jpg', '2017-07-05', 13.39, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1226, 'The Amazing Spider-Man', 'Peter Parker is an outcast high schooler abandoned by his parents as a boy, leaving him to be raised by his Uncle Ben and Aunt May. Like most teenagers, Peter is trying to figure out who he is and how he got to be the person he is today. As Peter discovers a mysterious briefcase that belonged to his father, he begins a quest to understand his parents\' disappearance â€“ leading him directly to Oscorp and the lab of Dr. Curt Connors, his father\'s former partner. As Spider-Man is set on a collision course with Connors\' alter ego, The Lizard, Peter will make life-altering choices to use his powers and shape his destiny to become a hero.', 'https://image.tmdb.org/t/p/w500/jexoNYnPd6vVrmygwF6QZmWPFdu.jpg', '2012-06-23', 9.26, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1227, 'The Amazing Spider-Man 2', 'For Peter Parker, life is busy. Between taking out the bad guys as Spider-Man and spending time with the person he loves, Gwen Stacy, high school graduation cannot come quickly enough. Peter has not forgotten about the promise he made to Gwenâ€™s father to protect her by staying away, but that is a promise he cannot keep. Things will change for Peter when a new villain, Electro, emerges, an old friend, Harry Osborn, returns, and Peter uncovers new clues about his past.', 'https://image.tmdb.org/t/p/w500/dGjoPttcbKR5VWg1jQuNFB247KL.jpg', '2014-04-16', 10.10, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1228, 'Spider-Man 3', 'The seemingly invincible Spider-Man goes up against an all-new crop of villainsâ€”including the shape-shifting Sandman. While Spider-Manâ€™s superpowers are altered by an alien organism, his alter ego, Peter Parker, deals with nemesis Eddie Brock and also gets caught up in a love triangle.', 'https://image.tmdb.org/t/p/w500/qFmwhVUoUSXjkKRmca5yGDEXBIj.jpg', '2007-05-01', 16.69, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1229, 'Spider-Man: Far From Home', 'Peter Parker and his friends go on a summer trip to Europe. However, they will hardly be able to rest - Peter will have to agree to help Nick Fury uncover the mystery of creatures that cause natural disasters and destruction throughout the continent.', 'https://image.tmdb.org/t/p/w500/4q2NNj4S5dG2RLF9CpXsej7yXl.jpg', '2019-06-28', 14.92, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1230, 'Spider-Man: Brand New Day', 'The fourth installment in the MCU Spider-Man series. Details TBA.', 'https://image.tmdb.org/t/p/w500/9JCQtDCSpPR2ld55yNlEg1VwcQo.jpg', '2026-07-30', 11.55, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Science Fiction'),
(1231, 'Spider-Man: Beyond the Spider-Verse', 'Miles Morales is now a fugitive on the run from every other Spider in the multiverse, and Gwen and his other friends might not be enough to help him.', 'https://image.tmdb.org/t/p/w500/rZ4arzyaDyI8l9Y7VIPPsDGARwh.jpg', '2027-06-02', 19.26, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Animation'),
(1232, 'Spider-Man 2', 'Peter Parker is going through a major identity crisis. Burned out from being Spider-Man, he decides to shelve his superhero alter ego, which leaves the city suffering in the wake of carnage left by the evil Doc Ock. In the meantime, Parker still can\'t act on his feelings for Mary Jane Watson, a girl he\'s loved since childhood. A certain anger begins to brew in his best friend Harry Osborn as well...', 'https://image.tmdb.org/t/p/w500/aGuvNAaaZuWXYQQ6N2v7DeuP6mB.jpg', '2004-06-25', 18.74, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Action'),
(1233, 'Daredevil vs. Spider-Man', 'Spider-Man and Daredevil team up to fight Kingpin.', 'https://image.tmdb.org/t/p/w500/mEtyZBbVl0sx0y1blYuVDgeNLkr.jpg', '2003-02-11', 8.70, '2025-04-14 20:31:29', '2025-04-14 20:31:45', 'Animation'),
(1251, 'Spider-Man: The Venom Saga', 'A space-shuttle crash-landing puts the famous web-slinger Spider-Man in contact with a living alien substance that bonds to his suit and enhances his super-powers. Unfortunately, the alien substance begins to change him and he feels the pull of evil, so discards the suit. The evil attaches itself to another host leading to an epic confrontation between good and evil.', 'https://image.tmdb.org/t/p/w500/vvYt1CDagCKMrolohME0o15GPZ3.jpg', '2005-06-07', 15.60, '2025-04-14 20:31:35', '2025-04-14 20:31:45', 'Animation'),
(1254, 'The Spider', 'Teenagers from a small town and their high school science teacher join forces to battle a giant mutant spider, living in a cave nearby and getting hungry.', 'https://image.tmdb.org/t/p/w500/4uns8WSxu9LSFv0FkJP8uv6Q5kQ.jpg', '1958-09-01', 14.99, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Horror'),
(1255, 'Spider Lilies', 'When Jade, a web-cam girl, visits Takeko\'s tattoo studio she becomes entranced with the image of the spider lily and with Takeko as well. In order to get closer to the object of her desire, Jade asks Takeko to give her the same lily tattoo, challenging Takeko\'s monastic existence and opening up memories which threaten to tear the two women apart.', 'https://image.tmdb.org/t/p/w500/zAoEHYqsr90pQG6C9ORNPzKDP6d.jpg', '2007-03-30', 13.81, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Drama'),
(1259, 'Li\'l Spider Girl', 'This story involves the shopkeeper Suzuri of Kokumondou who sells historic books and Mizuki, granddaughter of the land owner.  When Mizuki releases a somewhat cute young spider demon out of a sealed book, the pair investigate the origins behind it.', 'https://image.tmdb.org/t/p/w500/wafbftomue5BnIsSXN2ircyBMQh.jpg', '2012-03-12', 18.10, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Animation'),
(1260, 'Spider', 'A mentally disturbed man takes residence in a halfway house. His mind gradually slips back into the realm created by his illness, where he replays a key part of his childhood.', 'https://image.tmdb.org/t/p/w500/zvm4WuYxTiGkRagRqHUey0meRQL.jpg', '2002-11-06', 11.43, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Drama'),
(1261, 'Horrors of Spider Island', 'A bite from a giant spider turns a man into a creature that terrorizes a group of women who survived a plane crash.', 'https://image.tmdb.org/t/p/w500/psLNIMpkQpUneez3lZOo20GMBtR.jpg', '1960-04-15', 17.61, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Horror'),
(1264, 'Spider in the Web', 'A young operative is sent on a mission to follow an older agent who\'s behavior has come into question.', 'https://image.tmdb.org/t/p/w500/wTJc61L6ZeWjgUnIPXxKes27YpQ.jpg', '2019-04-20', 10.83, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Thriller'),
(1265, 'The Spider and the Butterfly', 'Surviving fragment of a longer film. A magician makes a butterfly woman appear, and a woman in a star.  Exhausted, the magician falls asleep and the star woman turns into a spider, dragging the butterfly into her web.', 'https://image.tmdb.org/t/p/w500/vMb2Ro7ZEtA6HAVLAOtDdlgb27r.jpg', '1909-02-27', 12.38, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Horror'),
(1266, 'Si-Sei 2 -The Fallen Spider-', 'A tattoo changes a woman. A tattoo changes a man. Tattoo is everything ... Asami, a woman who breaks into an affair with a man who has a wife the name is Ninomiya, a man who leaves the house apart from his wife and is inviting a self-development seminar to live today. The two who atoned for the past and asked for salvation met by chance. Asami, who decided to carve a tattoo by her own choice, entrusts her skin to a genius skin carver, Kokari. Eventually, a splendid woman\'s tattoo leaps on her back, which dramatically changes herself. Tattoo greatly changes Ninomiya\'s way of life and captivates the sculpture that dreams of the completion of tattoos. Eventually, the fate of men and women who were tossed by tattoos began to fluctuate greatly.', 'https://image.tmdb.org/t/p/w500/8lSFYVe0xmvXl6BFBY7lO0NOxKm.jpg', '2007-01-13', 14.32, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Drama'),
(1270, 'Big Ass Spider!', 'When a giant alien spider escapes from a military lab and rampages across the city of Los Angeles, it is up to one clever exterminator and his security guard sidekick to kill the creature before the entire city is destroyed.', 'https://image.tmdb.org/t/p/w500/uW4ayPN4B1mjrwb3OURRy0m9Hh7.jpg', '2013-10-17', 7.61, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Science Fiction'),
(1271, 'No Way, Spider', 'Spider, a banker, lives with three women. This tycoon is a caricature of Brazil\'s bourgeoisie, his trajectory is the starting point for an essay on the mental underdevelopment of Brazilian elites, in which black humor sets the tone for sharp criticism.', 'https://image.tmdb.org/t/p/w500/2Nym9dXRG5m7x9hWHeWYwuZ85HC.jpg', '1970-04-09', 16.02, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Comedy'),
(1273, 'Holy Spider', 'A journalist descends into the dark underbelly of the Iranian holy city of Mashhad as she investigates the serial killings of sex workers by the so called \"Spider Killer\", who believes he is cleansing the streets of sinners.', 'https://image.tmdb.org/t/p/w500/6ObJ4x7m1F5QRY06WzOxNJQHwGb.jpg', '2022-07-13', 18.99, '2025-04-14 20:31:37', '2025-04-14 20:31:37', 'Drama'),
(1293, 'The Spider-Man', 'Adaptation of Edogawa Ranpo\'s novel.', 'https://image.tmdb.org/t/p/w500/8qqeiVkNHjLOVu0jvRr44UbAvkF.jpg', '1958-06-29', 7.59, '2025-04-14 20:31:45', '2025-04-14 20:31:45', 'Mystery'),
(1294, 'Eternal Sunshine', 'For years single parent Mei Chun has been raising her mentally handicapped son Ray on her own. She is used to the challenges as an around-the-clock caregiver of the grown-up son. While her patience may wear thin at times, she remains tender and has formed a strong and unique bond with Ray. When a sudden sickness strikes, however, Mei Chun is burdened with a difficult decision. The night falls, but will dawn come?', 'https://image.tmdb.org/t/p/w500/iyQPQhfsjc8YHQ2ricIrjookqPt.jpg', '2020-06-09', 18.78, '2025-04-14 20:32:16', '2025-04-14 20:32:16', 'Drama'),
(1295, 'Eternal Sunshine of the Spotless Mind', 'Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.', 'https://image.tmdb.org/t/p/w500/5MwkWH9tYHv3mV9OdYTMR5qreIz.jpg', '2004-03-19', 18.72, '2025-04-14 20:32:16', '2025-04-14 20:32:16', 'Science Fiction'),
(1297, 'Eternal Sunshine Life-saving Squad', 'In 2000, cases of charcoal-burning suicide were increasing on the island Cheung Chau. The islanders\' livelihood was affected so they formed the life-saving squad. The guesthouse owner set up â€œ The Three No\'s Rental Rulesâ€. The part-time girl at the supermarket observed customers who might buy charcoal for suicide. Some islanders were on the lookout for distressed visitors. Occasionally, they succeeded in stopping the tragedy. Some survivors even joined the squad. At times, they made funny mistakes and met with hiccups in the life-saving endeavors. With trial and error, they explored the essential needs in people\'s hearts.', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 12.03, '2025-04-14 20:32:16', '2025-04-14 20:32:16', 'unknown'),
(1298, 'Eternal Whispers of Sunshine', 'Several shots during daylight reflecting life itself, and how the light fades through time.', 'https://image.tmdb.org/t/p/w500/cGyVbC3Xhrv1ng2usVj5H265w1E.jpg', '2024-11-09', 16.92, '2025-04-14 20:32:16', '2025-04-14 20:32:16', 'Drama'),
(1299, 'Titanic', '', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 12.86, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'unknown'),
(1306, 'Titanic, Suitable Version for Iranian Families', 'A complex and sometimes combative exchange at an Iranian broadcaster over a certain Hollywood blockbuster disguises deeper ruptures, in Farnoosh Samadiâ€™s wry and subtly provocative drama.', 'https://image.tmdb.org/t/p/w500/pFQf4YMpqRnerJIal1GET0Sclci.jpg', '2023-09-20', 15.33, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Animation'),
(1307, 'The Blind Man Who Did Not Want to See Titanic', 'Jaakko and Sirpa have never met face to face, but talk on the phone every day. When Jaakko hears news about Sirpa\'s declining health, he decides to go meet her in another city. It\'s not the easiest decision, because he\'s blind and paralyzed from the chest down  - and he has to make the journey alone. To get there, Jaakko must rely on the help of five strangers. What could go wrong?', 'https://image.tmdb.org/t/p/w500/lYuZ8yvVuUJsISKY75yt6FIzJFb.jpg', '2021-09-10', 12.68, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Drama'),
(1308, 'Titanic: Into the Heart of the Wreck', 'The Titanic is under a new threat. Resting at over 12,500 feet below sea level and 380 nautical miles off the coast of Newfoundland, the most famous shipwreck in the world is being consumed by a colony of iron-eating bacteria. This slow and irreversible decay, according to the most concerned experts, will sweep away all the secrets of the mythic liner within a few decades. This documentary details the underwater odyssey of the greatest Titanic expeditions and the evolution of the most scrutinized shipwreck in the world. From the epic discovery of the wreck by a French-American team in 1985 to the exploratory missions led by James Cameron, and to the treasure hunts that brought back over 5,000 vestigesâ€“experience the unequaled thrill of these extreme dives through the eyes of the explorers who have attempted to unlock Titanicâ€™s secrets.', 'https://image.tmdb.org/t/p/w500/sTqXfXdLtVBhWyo1kBG1xgtV946.jpg', '2020-12-17', 18.50, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Documentary'),
(1309, 'Titanic II', 'On the 100th anniversary of the original voyage, a modern luxury liner christened \"Titanic 2,\" follows the path of its namesake. But when a tsunami hurls an ice berg into the new ship\'s path, the passengers and crew must fight to avoid a similar fate.', 'https://image.tmdb.org/t/p/w500/3m12UeP1DMfhYZyvpLftaJGsyp3.jpg', '2010-08-07', 16.76, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Action'),
(1310, 'The Ten Lives of Titanic the Cat', 'A young girl finds excitement over the prospect of an ocean cruise, suddenly offset by a series of bizarre visions.', 'https://image.tmdb.org/t/p/w500/zJBSNGDMzL3EvQjuEzYqU0fB186.jpg', '2007-10-31', 15.45, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Mystery'),
(1311, 'Attack on Titan: THE LAST ATTACK', 'A colossal-sized omnibus film bringing together the last two episodes of Attack on Titan in the franchise\'s first-ever theatrical experience. After venturing beyond the walls and separated from his comrades, Eren finds himself inspired by this new truth and plots the \"Rumbling,\" a terrifying plan to eradicate every living thing in the world. With the fate of the world hanging in the balance, a motley crew of Eren\'s former comrades and enemies scramble to halt his deadly mission. The only question is, can they stop him?', 'https://image.tmdb.org/t/p/w500/aH0N5FnQsU38FJojQus8MUnGm0f.jpg', '2024-11-08', 12.27, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Animation'),
(1312, 'The Legend of the Titanic', 'Old Grandpa mouse tells to his grandchildren the \"real\" story of the Titanic disaster, including evil sharks, a giant octopus, and an evil whaling scheme.', 'https://image.tmdb.org/t/p/w500/tscmcvMs9T1TOjoMD7x12FveNsR.jpg', '1999-04-17', 14.34, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Animation'),
(1313, 'Raise the Titanic', 'To obtain a supply of a rare mineral, a ship raising operation is conducted for the only known source, the Titanic.', 'https://image.tmdb.org/t/p/w500/XvukyvRCbkYKKv1TdtlyNxvzEl.jpg', '1980-08-01', 18.36, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Adventure'),
(1314, 'Titanic Disaster', 'Incredibly fascinating documentary short that is a truly historic film. We see the actual Titanic leaving for its last voyage and also all the aftermath of the tragedy. We get to view various interesting aspects including seeing Captain Smith minutes before the boat sails, the Mary Sculley and the Carpathia in action, the Carpathia returning to the shore with survivors, Captain Rostrum of the Carpathia, family members at the White Star Office in NY waiting for news and even some of the survivors pulled off the lifeboats. Anyone interested in this historic event would certainly find this film fascinating and it\'s pretty sad and spooky to watch it today.', 'https://image.tmdb.org/t/p/w500/x4hs14VdqYeo0wM2YQjC5zGIRfd.jpg', '1912-01-01', 15.66, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Documentary'),
(1315, 'Unsinkable: Titanic Untold', 'The true story of rushed investigations, political interference, and the grasp for corporate accountability woven amongst heart wrenching flashbacks of the Titanic disaster as it unfolded.', 'https://image.tmdb.org/t/p/w500/xPBxayYhw7m2dN89NgsZ9JStreF.jpg', '2024-03-10', 7.40, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Drama'),
(1316, 'Titanic Waltz', 'Based on a play by Tudor MuÈ™atescu, Titanic Vals is the essence of Romanian genius in comedy, with amazing performances and the beautiful absurd of the quotidian.', 'https://image.tmdb.org/t/p/w500/ezr00Sm1H6Qlq7hRrUZQ9IP7PF3.jpg', '1965-01-25', 8.19, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Comedy'),
(1317, 'Words of the Titanic', 'Readings from the diaries, accounts and letters of its passengers and crew tell the story of the Titanic, which sank 100 years ago today on its maiden voyage. The cast includes Richard E Grant, Roger Allam, Anna Madeley, James Wilby and Claudie Blakley, alongside relatives of those who were on board. Charles Dance narrates.', 'https://via.placeholder.com/500x750?text=No+Image', '2012-04-15', 13.13, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Documentary'),
(1318, 'Last Year Titanic', 'Director Andreas Voigt interviewed people of different ages and social backgrounds about their experiences after the fall of the Berlin Wall. He paints an important picture of this historic period in German history, filled with radical social and economic change and insecurity. Last Year Titanic was shot from December 1989 through December 1990 â€” the last months of the GDR and the first months in united Germany.', 'https://image.tmdb.org/t/p/w500/kk8b0j1UvZhy5pByRupGJMp9B5T.jpg', '1991-02-23', 15.44, '2025-04-14 20:32:29', '2025-04-14 20:32:29', 'Documentary'),
(1319, 'Focus', 'A short, direct and to-the-point media-commentary thriller. A sleazy TV producer trying to exploit a quiet otaku (an obsessive hobbyist) whose hobby is electronic eavesdropping ends up getting a lot more than he bargained for when they eavesdrop on the wrong conversation and he prods said otaku into helping him \"investigate\" the lead, only to find out that some things (and people) are not always as they seem, when a minor altercation causes things to take a rather nasty turn....', 'https://image.tmdb.org/t/p/w500/2beMmdeesB0j3FRl5S4GHGmTJfq.jpg', '1996-10-12', 11.49, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'Thriller'),
(1332, 'Zero Focus', 'Spurred by the disappearance of a newly-wed husband, three women in post-war Japan are drawn into a murder mystery.', 'https://image.tmdb.org/t/p/w500/7yTM8x9PGk5oJRwPTlzJosANCA3.jpg', '2009-11-14', 11.90, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'Drama'),
(1333, 'Gen\'eki Joshidaisei: Kahanshin Focus', '', 'https://image.tmdb.org/t/p/w500/ApK0XnsD36IMtitwRwPgdTojKah.jpg', '1986-07-12', 11.82, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'unknown'),
(1334, 'Out of Focus', 'Starting from a photography workshop for \"immigrant children\", the filmmaker focuses on Qin, in a harsh and unsettling portrait.', 'https://image.tmdb.org/t/p/w500/nCvkqSfjcL7XnKO6ebQewwVEDsI.jpg', '2014-03-26', 17.50, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'Documentary'),
(1335, 'Focus T25: Alpha - Speed 1.0', 'Ignite your quickness. Burn the fat. Fast-paced for fast results.', 'https://image.tmdb.org/t/p/w500/tmn0j1QL6cWG6RYEezAHAvNhvNE.jpg', '2013-01-01', 18.76, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'unknown'),
(1336, 'Auto Focus', 'A successful TV star during the 1960s, former \"Hogan\'s Heroes\" actor Bob Crane projects a wholesome family-man image, but this front masks his persona as a sex addict who records and photographs his many encounters with women, often with the help of his seedy friend, John Henry Carpenter. This biographical drama reveals how Crane\'s double life takes its toll on him and his family, and ultimately contributes to his death.', 'https://image.tmdb.org/t/p/w500/rgXN6YTZ0qvgVyZhojEtUwJDH0B.jpg', '2002-10-18', 13.53, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'Crime'),
(1337, 'Focus Iran', 'A documentary on women photographers in present-day Iran, exploring their motivations as well as the many obstacles they face along the way.', 'https://image.tmdb.org/t/p/w500/no4tED1YfS3SBLlbSxGRG6uJLt9.jpg', '2017-09-19', 17.71, '2025-04-14 20:32:48', '2025-04-14 20:32:48', 'Documentary'),
(1339, 'American Beauty', 'Millicent Howard, whose appearance and persona bring her a life of luxury. A millionaire named Claverhouse asks her to marry, but she values love more than wealth, and she sacrifices everything for another man, who is less wealthy, Jerry Booth. A lost film.', 'https://image.tmdb.org/t/p/w500/yOC4U0iFM4kFUdUOqVBIfMhPvIm.jpg', '1927-10-09', 6.36, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Comedy'),
(1342, 'The American Beauty', 'Marcel, a simple-minded factory worker, is tricked into buying a high-priced American convertable car by a widow determined not to let it fall into the hands of her late husband\'s secretary/secret lover. Once in pocession of the car, Marcel only encounters one bad luck episode after another with the excessive gasoline consumtion, his wife trying to sell it to make ammends meet, getting into traffic jams, accidently riding into a car wash with the top down, and more.', 'https://image.tmdb.org/t/p/w500/zyYTH4t5fEf66fpSP9L2vBIeebI.jpg', '1961-09-29', 7.19, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Comedy'),
(1343, 'The Great American Beauty Contest', 'The pursuit by America\'s loveliest girls for a coveted beauty crown is threatened by a scandal which implicates a judge, a former winner, and one of the five finalists.', 'https://image.tmdb.org/t/p/w500/gMkiPNeXV8sk1DLTLVnS1JJjzzB.jpg', '1973-02-13', 14.63, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'TV Movie'),
(1344, 'American Beauty: Look Closer...', 'A promotional short documentary on the making of the film American Beauty, directed by Sam Mendes and written by Alan Ball.', 'https://image.tmdb.org/t/p/w500/vzIaeW2iGAgNkT48jpO3cn5yxlY.jpg', '2000-10-24', 13.52, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Documentary'),
(1345, 'American Black Beauty', 'After her father dies in a horse riding accident, a displaced city girl named Cheryl is sent to live with a foster family on a farm in the country. Here she meets a magnificent horse. Cheryl learns to face her fear of horses and manages to race once again.', 'https://image.tmdb.org/t/p/w500/nLj3HfUSMTYW4RfjBpnal6Up1Xk.jpg', '2005-05-31', 17.76, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Family'),
(1346, 'Miss All-American Beauty', 'After winning a beauty contest in Texas, a teenage girl is unprepared for the demands of travel, press conferences and interviews that go with winning the title and participating in a national beauty pageant.', 'https://image.tmdb.org/t/p/w500/iYjDhG4sZBhIKV5Gr5OReYtBjmh.jpg', '1982-12-27', 18.17, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Comedy'),
(1347, 'American Beauty Ltd.', 'From the turn of the century - as emigrants to a New World - through the twenties and through the thirties - with great industry and the Great Depression - and finally during Detroit\'s heroic period in World War II - working in the armaments industry, the \"arsenals of democracy.\" What remains when such men\'s dreams become real?', 'https://via.placeholder.com/500x750?text=No+Image', '1989-01-01', 6.53, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Documentary'),
(1348, 'American Beauty Ã€ La John Wilson', 'Courtesy of the Assistant Editors of HOW TO, an homage to an infamous moment from AMERICAN BEAUTY, John Wilson-style.', 'https://via.placeholder.com/500x750?text=No+Image', '2023-08-19', 6.59, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'unknown'),
(1349, 'Taylor Swift: American Beauty', 'Biography - Taylor Alison Swift has evolved into one of the most popular names in modern music. Her strong voice and natural charm has made her the most successful country music artist in history. At the tender age of 21, she\'s already sold over 34 million digital tracks alone. However her success is no coincidence! Taylor Swift is one of the hardest working performers in music. This biography picture goes beyond the music and explores the challenges and triumphs of Taylor Swift, the American Beauty. -  Kathie Bostian, Holly Burns, Reid Cox', 'https://via.placeholder.com/500x750?text=No+Image', '2012-01-03', 19.75, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Documentary'),
(1350, 'Dorothy Dandridge: An American Beauty', 'Actor Obba BabatundÃ© hosts this biopic showcasing the life of acclaimed African-American singer and actress Dorothy Dandridge, who overcame racism and personal tragedy to become one of the most acclaimed performers of Hollywood\'s golden age. The film combines rare historical footage of Dandridge, on and off the stage, and interviews with stars such as Laurence Fishburne, Jasmine Guy and Halle Berry discussing her powerful legacy.', 'https://image.tmdb.org/t/p/w500/gCSAAr4qi0yQhAL8cS9CiG3WNhS.jpg', '2003-06-24', 17.89, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Documentary'),
(1351, 'No Lye: An American Beauty Story', 'A documentary that chronicles the rise and decline of the black-owned ethnic beauty industry in America.', 'https://image.tmdb.org/t/p/w500/tZKLBC9eWJDoxspuF0emkgbyPLG.jpg', '2019-11-28', 16.05, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Documentary'),
(1352, 'Sports Illustrated: Swimsuit 2004', 'Sports Illustrated\'s 40th Anniversary Swimsuit Edition.  Tyra Banks, Heidi Klum, Marisa Miller, and many of the popular models come back for the 40th.', 'https://image.tmdb.org/t/p/w500/co1etD0J4wnawGk49ZeayuJ0HKJ.jpg', '2004-02-10', 19.77, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'unknown'),
(1353, 'Ebony, Ivory & Jade', 'An American track team has just arrived in The Philippines for an international competition. Among the competitors are Ginger and Pam, nicknamed \"Ivory\" and \"Ebony\", who meet up with another friend, Jackie, nicknamed \"Jade\". After they arrive at their hotel, a gang of thugs kidnaps them, along with some other girls from the team. To get away, the trio are going to have to use all their fighting skills.', 'https://image.tmdb.org/t/p/w500/sPqNHV8kOXZ0QGhxDuQt7duAtre.jpg', '1976-09-24', 8.32, '2025-04-14 20:33:02', '2025-04-14 20:33:02', 'Action'),
(1354, 'The Seventh Company Outdoors', 'The third part of Seventh Company adventures.', 'https://image.tmdb.org/t/p/w500/qNBJf3mEfKmoB2iKAlAY3ux9wMB.jpg', '1977-12-07', 9.53, '2025-04-14 20:33:15', '2025-04-14 20:33:15', 'Comedy');
INSERT INTO `movies` (`id`, `title`, `description`, `poster_path`, `release_date`, `price`, `created_at`, `updated_at`, `category`) VALUES
(1355, 'Now Where Did the Seventh Company Get to?', '1940: During the chaotic running fights of the French army the 7th company disappears - nobody knows they\'ve been taken captive. Only their scouting patrol, three witty but lazy guys, can escape and now wanders around behind the German lines. They\'d like to just stay out the fights, but a Lieutenant urges them to use a captured truck to break through to their troops.', 'https://image.tmdb.org/t/p/w500/eGbSIQ9HumvikBxllond5uCVXjp.jpg', '1973-05-24', 17.04, '2025-04-14 20:33:15', '2025-04-14 20:33:15', 'Comedy'),
(1356, 'The Seventh Company Has Been Found', 'The second part of the Seventh Company adventures.', 'https://image.tmdb.org/t/p/w500/oBsGkRLaeZzoJr4qnlyF6wZQst9.jpg', '1975-12-10', 13.44, '2025-04-14 20:33:15', '2025-04-14 20:33:15', 'Comedy'),
(1357, 'Men in Black', 'The stooges are three doctors who graduated medical school by being in it for too many years. They come across such problems as an overly chirpy nurse, a mental patient, and a combination to a safe swallowed by the hospital superintendent in the course of their attempt to get through the day.', 'https://image.tmdb.org/t/p/w500/2kBOhxpwc7ZHO6Y3CzKTrhtkTO4.jpg', '1934-09-28', 6.35, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Comedy'),
(1359, 'Men Suddenly in Black 2', '', 'https://image.tmdb.org/t/p/w500/hF5FGT3xmfkOuSxkqWiit9F7qjV.jpg', '2006-09-08', 8.62, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Comedy'),
(1360, 'Men in Black 3', 'Agents J and K are back...in time. J has seen some inexplicable things in his 15 years with the Men in Black, but nothing, not even aliens, perplexes him as much as his wry, reticent partner. But when K\'s life and the fate of the planet are put at stake, Agent J will have to travel back in time to put things right. J discovers that there are secrets to the universe that K never told him - secrets that will reveal themselves as he teams up with the young Agent K to save his partner, the agency, and the future of humankind.', 'https://image.tmdb.org/t/p/w500/90DdoEStzeObs96fsYf4GG544iN.jpg', '2012-05-23', 19.00, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Action'),
(1361, 'Men Suddenly in Black', 'Four men attempt to fool around as much as they can before their wives return from a 14-hour Buddhism trip to Thailand.', 'https://image.tmdb.org/t/p/w500/l66GCI5G3mXFSQw5JY6daglQdPj.jpg', '2003-08-11', 11.93, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Comedy'),
(1362, 'Men in Black II', 'Kay and Jay reunite to provide our best, last and only line of defense against a sinister seductress who levels the toughest challenge yet to the MIB\'s untarnished mission statement â€“ protecting Earth from the scum of the universe. It\'s been four years since the alien-seeking agents averted an intergalactic disaster of epic proportions. Now it\'s a race against the clock as Jay must convince Kay â€“ who not only has absolutely no memory of his time spent with the MIB, but is also the only living person left with the expertise to save the galaxy â€“ to reunite with the MIB before the earth submits to ultimate destruction.', 'https://image.tmdb.org/t/p/w500/enA22EPyzc2WQ1VVyY7zxresQQr.jpg', '2002-07-03', 10.03, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Action'),
(1363, 'Men in Black: International', 'The Men in Black have always protected the Earth from the scum of the universe. In this new adventure, they tackle their biggest, most global threat to date: a mole in the Men in Black organization.', 'https://image.tmdb.org/t/p/w500/dPrUPFcgLfNbmDL8V69vcrTyEfb.jpg', '2019-06-12', 10.26, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Comedy'),
(1364, 'Black Men in Uniform', 'Pata Seca  (1828), a man whose back bore the whip marks of his enslavers , whose eyes held the haunted memory of being forced to breed over 200 slave children in order to sustain his masterâ€™s plantation.  Men broken but unbowed, transformed from field hands into soldiers from the civil war to Vietnam.  This documentary weaves together authentic narratives from the 1800s, accompanied by original images and footage, highlighting the significant influence that Black men in uniform had in Hollywood and addressing ongoing relevant issues to date.', 'https://image.tmdb.org/t/p/w500/tZmufORYoqWfjYDxblpBSiHlQEk.jpg', '2026-01-01', 17.35, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Documentary'),
(1365, 'Detective Conan Drama Special 2: Confrontation With the Men in Black', 'Shinichi Kudo returns as the young Conan to investigate a murderous letter sent to a beauty pageant winner who demands affection.', 'https://image.tmdb.org/t/p/w500/AnWR6Jk3kKJA7j010YAtWkSWoyQ.jpg', '2007-12-17', 16.86, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Mystery'),
(1366, 'Who Saw the Men in Black', 'Who are the Men in Black? Many have reported their own Men in Black experiences and eye witness accounts since the beginning of the UFO cover-up history. Walk through the true history of Men in Black events from the 1940s until now.', 'https://image.tmdb.org/t/p/w500/yJSTW2MEvUH7sKqExflaioHMQyG.jpg', '2021-11-09', 17.44, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Documentary'),
(1367, 'Tales of Terror: Men in Black', 'Kyoka, a university student, receives an old brown envelope in which she finds a photograph of her classmate, Sachiko. With this, she also finds a mysterious message saying \"Help me\". One day, while at a cafÃ©, Kyoka overhears that \"somebody had been spirited away by a man in a black suit\". It was at that moment that Kyoka recalled the moment that Sachiko had suddenly disappeared in the mountains right in front of her very own eyes.', 'https://image.tmdb.org/t/p/w500/aIIwhxwiopY1xNGFQ6vQJIrxMHW.jpg', '2007-06-30', 14.42, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Horror'),
(1368, 'Metamorphosis of \'Men in Black\'', 'An in-depth look into the creation of the special effects for the film Men in Black (1997). Various interviews with the cast and filmmakers and a look at the pre-rendered SFX from ILM and Rick Baker. Also a look at storyboards and information about the change of the script during production.', 'https://image.tmdb.org/t/p/w500/5ax0t8bU8E5JhtxkPGQT48TSOvZ.jpg', '2000-09-05', 14.74, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Documentary'),
(1369, 'Design in Motion: The Look of \'Men in Black II\'', 'A look at the art direction of Men in Black II (2002)', 'https://image.tmdb.org/t/p/w500/i12BzsvVF8yofENLfH1Mjo04lPb.jpg', '2002-11-26', 14.11, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Documentary'),
(1370, 'The Making of Men in Black', 'Behind the scenes of Men in Black (1997)', 'https://image.tmdb.org/t/p/w500/31l8XyHx7sRI1nbIh5SfBRXHOw7.jpg', '1997-11-04', 18.58, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Documentary'),
(1371, 'The Other Men in Black', 'A young film student finds creative inspiration in her grandfather\'s stories about the Hasidic movement, its history, beliefs, and impact on Jewish culture.', 'https://image.tmdb.org/t/p/w500/tvSsq8eRpbhTQkHINeGbun2nTbx.jpg', '2013-04-30', 11.17, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'unknown'),
(1372, 'Untitled Men in Black Film', 'A new \'Men in Black\' film is reportedly in the works at Sony Pictures.', 'https://image.tmdb.org/t/p/w500/hpDyZK9ZHSWVSztfhwyhGVDSOp2.jpg', NULL, 19.27, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Science Fiction'),
(1373, 'The Men in Black', 'Psychiatrist, Conrad O\'Brien (played by Doug Wertz), faces his own struggles. Recently divorced and the feeling of losing balance and trust of his own patients, he starts to self medicate to overcome. But then he believes he saw something that changes to course of everything. Is it real or is his life too overwhelming?', 'https://image.tmdb.org/t/p/w500/7EZbeIRYnvzO60Lt4mKmuAzpfNz.jpg', '1992-11-07', 11.52, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Science Fiction'),
(1374, 'Squish, Splat, Sploosh: The Stellar Sounds of \'Men in Black II\'', 'A look behind the scenes of MIIB to watch the foley artists at work adding all the background and special effects noises to the finished scenes. Covering everything from an alien battle to Agent J walking across a floor, we see what they use and how they use it.', 'https://image.tmdb.org/t/p/w500/y9lZaXvQ600DLnAEQxGgzyYatvn.jpg', '2002-11-26', 14.46, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Documentary'),
(1375, 'Alien Paranormal: Bigfoot, UFO\'s and the Men in Black', 'Are Bigfoot creatures traveling to earth in UFO\'s, while being covered-up by mysterious men in black? UFO investigator Stan Gordon lays out the research and evidence in this mind-blowing journey into a very strange territory.', 'https://image.tmdb.org/t/p/w500/xQqWe1S0clfnjN6d9QJHAWRuBKF.jpg', '2013-01-01', 8.09, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'unknown'),
(1376, 'Satan Met a Lady', 'In the second screen version of The Maltese Falcon, a detective is caught between a lying seductress and a lady jewel thief.', 'https://image.tmdb.org/t/p/w500/sv7TKzYhq3qybbgTr9Z0Em0BiLj.jpg', '1936-07-22', 18.20, '2025-04-14 20:33:22', '2025-04-14 20:33:22', 'Comedy'),
(1377, 'Oppenheimer', 'The story of J. Robert Oppenheimer\'s role in the development of the atomic bomb during World War II.', 'https://image.tmdb.org/t/p/w500/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg', '2023-07-19', 18.48, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Drama'),
(1378, 'The Ballad of Oppenheimer Park', 'The Ballad of Oppenheimer Park is a film that celebrates the everyday life of a group of Indigenous people, exiles from Canadian reserves, who, over a fleeting summer, hang out in a contested park in Vancouver. Through direct participation in the filmmaking process, the day to day becomes a ceremonial space in the ongoing confrontation against law and order.', 'https://image.tmdb.org/t/p/w500/x2I6MgQOpOvtWGzZZ2LktFlF5MQ.jpg', '2016-03-09', 13.30, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1379, 'To End All War: Oppenheimer & the Atomic Bomb', 'Explore how one man\'s relentless drive and invention of the atomic bomb changed the nature of war forever, led to the deaths of hundreds of thousands of people and unleashed mass hysteria.', 'https://image.tmdb.org/t/p/w500/xwkYWcs8aypUtk3xDRUh0ndo4GA.jpg', '2023-07-09', 17.78, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1380, 'The Oppenheimer Case', 'During World War II, the American physicist Robert Oppenheimer was at the head of the research work for the production of the atomic bomb. He was removed from that position in 1953 due to disagreements with the US Atomic Commission regarding the development of the hydrogen bomb. The investigation that was conducted against him during the infamous time of anti-communist hysteria and the \"witch hunt\" during the time of Senator McCarthy is testimony to the great moral and psychological dilemma in which the scientists of that era found themselves.', 'https://image.tmdb.org/t/p/w500/1ufp5zjkkjXoSHLN7milIPNOZtS.jpg', '1970-02-02', 6.59, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Drama'),
(1381, 'The Trials of J. Robert Oppenheimer', 'J. Robert Oppenheimer was a national hero, the brilliant scientist who during WWII led the scientific team that created the atomic bomb. But after the bomb brought the war to an end, in spite of his renown and his enormous achievement, America turned on him - humiliated and cast him aside. The question the film asks is, \"Why?\"', 'https://image.tmdb.org/t/p/w500/nw2snwOxddwZRhDL1cW9q3Lr9Gt.jpg', '2008-03-24', 9.51, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1382, 'Oppenheimer and The Manhattan Project', 'Delves deep into the life and complex legacy of J. Robert Oppenheimer, one of the most enigmatic and influential figures of the 20th century.', 'https://image.tmdb.org/t/p/w500/xAHfLoQgTOuzABAXqlhQtdrujB2.jpg', '2024-10-01', 6.60, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1383, 'Inside Christopher Nolan\'s Oppenheimer', 'A look behind the scenes of Christopher Nolan\'s film \"Oppenheimer\" about an American scientist and his role in the development of the atomic bomb.', 'https://image.tmdb.org/t/p/w500/p3mB2IFZAhFlBPwlNbv2ouzwxx0.jpg', '2023-07-15', 19.53, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1384, 'Oppenheimer: The Real Story', 'J. Robert Oppenheimer, a physics professor known for creating the atomic bomb during WWII. He witnessed the first atomic bomb detonation in New Mexico in 1945. This film examines Oppenheimer\'s life, from his early years to his involvement with nuclear physics and his later advocacy for nuclear weapons controls, with interviews and insights from those who knew him and impacted by his legacy.', 'https://image.tmdb.org/t/p/w500/ecYTEmn3JBZyWbqwzjmBFfGvi3U.jpg', '2023-07-17', 9.41, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1385, 'Oppenheimer After Trinity', 'This captivating documentary on J. Robert Oppenheimer, the architect of the atomic bomb, explores his journey before the historic test and reveals the burden he carried after. De-classified documents, rare film footage and exclusive interviews, including Oppenheimer\'s grandson, show an intimate exploration of the burden Oppenheimer carried and the profound global impact still being debated today.', 'https://image.tmdb.org/t/p/w500/6Mq4O6RyKXWnXOhor71qzV92n7n.jpg', '2023-04-22', 14.21, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1386, 'The Real Oppenheimer', '', 'https://image.tmdb.org/t/p/w500/jUqSMGViJoorV8bnZpgp6HXpG42.jpg', '2023-08-01', 13.21, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1387, 'Oppenheimer: Genius or Madman?', 'This documentary explores famous figure J. Robert Oppenheimer, an American theoretical physicist who was called, \"father of the atomic bomb\" for his role in the Manhattan Project.', 'https://image.tmdb.org/t/p/w500/86smfQwQPC81j02ELmalmQZu2OL.jpg', '2023-07-25', 7.43, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1388, 'In der Sache I. Robert Oppenheimer', '', 'https://via.placeholder.com/500x750?text=No+Image', '1964-01-23', 18.20, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'TV Movie'),
(1389, 'Innovations in Film: 65mm Black and White Film in Oppenheimer', 'FotoKem gives in-depth tour of the new scientific and artistic workflows that had to be invented in order to realize Christopher Nolan\'s unique vision of using both color and black & white 65mm film in the same motion picture', 'https://image.tmdb.org/t/p/w500/iClm6meiTIDJEYrl2zrwnxiwU4X.jpg', '2023-11-22', 18.72, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1390, 'The Oppenheim Family', 'Directed by Grigori Roshal.', 'https://image.tmdb.org/t/p/w500/kuOAkBeSnohQq9SGlpZaEER4jkt.jpg', '1939-01-02', 18.11, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'unknown'),
(1391, 'Oppenheimer: O GÃªnio Arrependido', '', 'https://image.tmdb.org/t/p/w500/znL8ZS2cZrv3mnfd0cBor6GSvB2.jpg', '2023-06-19', 19.27, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Drama'),
(1392, 'In der Sache J. Robert Oppenheimer', '', 'https://via.placeholder.com/500x750?text=No+Image', '1981-11-01', 8.10, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Drama'),
(1393, 'Josef SÃ¼ÃŸ Oppenheimer', '', 'https://via.placeholder.com/500x750?text=No+Image', '1984-01-24', 10.98, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Drama'),
(1394, 'Joshua Oppenheimer on Night and Fog', 'The Academy Award-winning director of the heavy documentary \'The Act of Killing\' discusses his philosophies in documentary filmmaking, the horrors of \'Night and Fog,\' and what makes it the impactful film that it is.', 'https://image.tmdb.org/t/p/w500/r2g5F3W6aAVwKrOzdOwXcMcP1Fu.jpg', '2016-07-19', 19.55, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Documentary'),
(1395, 'Schaffende HÃ¤nde: Max Oppenheimer', 'In the best films of Hans CÃ¼rlis the acts of filming and painting coincide. The portrait of a portraitist. Max Oppenheimer (Mopp; 1885-1954) was a well-known portraitist and painter of musicians and orchestras. In this case he paints the portrait of Heinrich Mann, while CÃ¼rlis portrays Heinrich Mann as he is being portrayed by Mopp and Mopp as he is portraying Heinrich Mann. Thus the \"Schaffende HÃ¤nde\" â€” Creative Hands â€” are both those of the painter and those of the film director CÃ¼rlis: these are hand-made films.', 'https://via.placeholder.com/500x750?text=No+Image', '1924-01-01', 7.41, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'unknown'),
(1396, 'Oppenheimerin tapaus', 'A television play adaptation of the trial against Robert Oppenheimer.', 'https://image.tmdb.org/t/p/w500/50Rov4ZLE88brOkKFt9GdkxDXYT.jpg', '1967-10-11', 14.38, '2025-04-14 20:33:43', '2025-04-14 20:33:43', 'Drama'),
(1397, 'A Minecraft Movie', 'Four misfits find themselves struggling with ordinary problems when they are suddenly pulled through a mysterious portal into the Overworld: a bizarre, cubic wonderland that thrives on imagination. To get back home, they\'ll have to master this world while embarking on a magical quest with an unexpected, expert crafter, Steve.', 'https://image.tmdb.org/t/p/w500/iPPTGh2OXuIv6d7cwuoPkw8govp.jpg', '2025-03-31', 6.50, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'Family'),
(1398, 'Minecraft: The Story of Mojang', 'Minecraft: The Story of Mojang is a feature-length documentary that follows the young company over the course of its first year as their profile expanded across the world stage and into the homes of millions of gamers. Featuring insights from industry icons, journalists, tastemakers, and players profoundly impacted by the game, the film serves as a time capsule for one of this generation\'s most unorthodox success stories.', 'https://image.tmdb.org/t/p/w500/2V3Tbq7xdRRw0G92Tx62IYDLz1g.jpg', '2012-12-23', 15.57, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'Documentary'),
(1399, 'Untitled A Minecraft Movie Sequel', 'The sequel to A Minecraft Movie. Plot TBA.', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 18.86, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'Family'),
(1400, 'Minecraft: The Story of Minecraft', 'Since its development in 2009, Minecraft has taken the digital world by storm. Itâ€™s now played by millions of people on a global scale. Its impact on the gaming community is unrivalled, so much so that Microsoft purchased Minecraft for an eye watering $2.5 billion. With new game modes being developed, there is every chance Minecraft will be the worlds No. 1 game for many years to come. With exclusive interviews from YouTube celebrities such as The Diamond Minecart and Ali A, as well as industry experts, this documentary takes an in depth look at how one game took over the gaming world. Get lost in a digital universe, follow the story of Minecraft.', 'https://image.tmdb.org/t/p/w500/dPbOs8EzEiLBb2k2Bq0k2LIDfez.jpg', '2016-08-09', 11.57, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'unknown'),
(1401, 'Minecraft: Into the Nether', 'Minecraft. The game that took the world by storm. Follow the story of how the Minecraft phenomenon has ploughed through the 21st century selling over 54 million copies worldwide on a multitude of platforms engaging an audience in the millions which is still continuing to grow. The game boasts the biggest digital world in gaming history with a fan base stretching to every corner of the globe. Youtube viewing numbers have grown and online participation has tripled over the last few years creating a new industry for enthusiastic gamers. Vast communities have been brought together through it\'s educational impact, YouTube celebrities, festivals and game events pushing the boundaries of technology and creativity to the limits.', 'https://image.tmdb.org/t/p/w500/vLci7Om940xXupc4kUPTC2JoGWW.jpg', '2015-01-27', 6.28, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'Documentary'),
(1402, 'Minecraft: Through the Nether Portal', 'Minecraft: Through the Nether Portal takes you on a journey through the ever-evolving, epic game of Minecraft. Its popularity is opening up a whole new world for this generation, with millions of new players signing up each week. With exclusive interviews from industry experts and Minecraftâ€™s biggest YouTube players, Dan TDM and Ali-A, we look at how the game is now being used as a tool for education and teaching while digging deeper into the creativity behind the game.', 'https://image.tmdb.org/t/p/w500/fLCB9f2zqdksQxLPUPJpPWUP7xL.jpg', '2017-05-16', 7.79, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'Documentary'),
(1403, 'Voyager Of Destiny: The Minecraft Fan Film', 'A story focusing on a gamer named Steve, who gets sucked into the world of \"Minecraft\". Being stuck in this vast world, a new friend appears, who may or may not have plans to take over Minecraft. Somebody\'s got to be the hero.', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 8.35, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'unknown'),
(1404, 'DAWN â€“ A Minecraft Fan Film', 'NOT AN OFFICIAL MINECRAFT FILM. NOT APPROVED BY OR ASSOCIATED WITH MOJANG OR MICROSOFT.  Minecraft and related IP are property of Mojang Studios. This unofficial fan film is not intended for commercial use and is not associated in any way with Mojang Studios. This is a passion project and was entirely self-funded.', 'https://image.tmdb.org/t/p/w500/2nNAeEjhK175ypWkryS3yOKhO7W.jpg', '2023-04-26', 15.36, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'unknown'),
(1405, 'Minecraft Mysteries', 'A detective is pulled through a series of unsettling events. This is his story.', 'https://via.placeholder.com/500x750?text=No+Image', '2020-06-11', 9.10, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'unknown'),
(1406, 'Minecraft: Il Film di Pete', '', 'https://image.tmdb.org/t/p/w500/38sEAplwSsG38clka0UtqNYeBoM.jpg', '2014-11-23', 15.20, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'Comedy'),
(1407, 'The Minecraft Movie Collection', 'Four misfits find themselves struggling with ordinary problems when they are suddenly pulled through a mysterious portal into the Overworld: a bizarre, cubic wonderland that thrives on imagination. To get back home, they\'ll have to master this world while embarking on a magical quest with an unexpected, expert crafter, Steve.', 'https://image.tmdb.org/t/p/w500/8jMQ2sVZ1RRiYSpcb7Yommo7V4r.jpg', NULL, 16.99, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'unknown'),
(1408, 'A Tribute to Minecraft', 'A retrospective on my favorite game, probably ever.', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 10.62, '2025-04-14 20:34:00', '2025-04-14 20:34:00', 'unknown'),
(1409, 'Boruto: Naruto the Movie', 'The spirited Boruto Uzumaki, son of Seventh Hokage Naruto, is a skilled ninja who possesses the same brashness and passion his father once had. However, the constant absence of his father, who is busy with his Hokage duties, puts a damper on Boruto\'s fire. He ends up meeting his father\'s friend Sasuke, and requests to become... his apprentice!? The curtain on the story of the new generation rises!', 'https://image.tmdb.org/t/p/w500/1k6iwC4KaPvTBt1JuaqXy3noZRY.jpg', '2015-08-07', 10.01, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Adventure'),
(1411, 'Naruto Shippuden the Movie', 'Demons that once almost destroyed the world, are revived by someone. To prevent the world from being destroyed, the demon has to be sealed and the only one who can do it is the shrine maiden Shion from the country of demons, who has two powers; one is sealing demons and the other is predicting the deaths of humans. This time Naruto\'s mission is to guard Shion, but she predicts Naruto\'s death. The only way to escape it, is to get away from Shion, which would leave her unguarded, then the demon, whose only goal is to kill Shion will do so, thus meaning the end of the world. Naruto decides to challenge this \"prediction of death.\"', 'https://image.tmdb.org/t/p/w500/vDkct38sSFSWJIATlfJw0l3QOIR.jpg', '2007-08-04', 19.37, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1412, 'Naruto the Movie: Legend of the Stone of Gelel', 'Naruto, Shikamaru, and Sakura are executing their mission of delivering a lost pet to a certain village. However, right in the midst of things, troops led by the mysterious knight, Temujin, attack them. In the violent battle, the three become separated. Temujin challenges Naruto to a fight and at the end of the fierce battle, both fall together from a high cliff...', 'https://image.tmdb.org/t/p/w500/itKMldwL6uhUZYO3X78NOFU4zzO.jpg', '2005-08-06', 16.19, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1413, 'Road to Ninja: Naruto the Movie', 'Sixteen years ago, a mysterious masked ninja unleashes a powerful creature known as the Nine-Tailed Demon Fox on the Hidden Leaf Village Konoha, killing many people. In response, the Fourth Hokage Minato Namikaze and his wife Kushina Uzumaki, the Demon Fox\'s living prison or JinchÅ«riki, manage to seal the creature inside their newborn son Naruto Uzumaki. With the Tailed Beast sealed, things continued as normal. However, in the present day, peace ended when a group of ninja called the Akatsuki attack Konoha under the guidance of Tobi, the mysterious masked man behind Fox\'s rampage years ago who intends on executing his plan to rule the world by shrouding it in illusions.', 'https://image.tmdb.org/t/p/w500/xLal6fXNtiJN6Zw6qk21xAtdOeN.jpg', '2012-07-28', 11.65, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1414, 'Naruto Shippuden the Movie: The Lost Tower', 'Assigned on a mission to capture Mukade, a missing-nin, Naruto Uzumaki sets out for the once glorious historic ruins of \"Ouran\", where he pursues and corners the rouge ninja. Mukade\'s goal is revealed to be a dormant leyline within the ruins; he unleashes the power of the leyline, causing a light to envelop Naruto, sending him into the past, 20 years before the series began. When Naruto awakens, he comes into contact with the Fourth Hokage, Minato Namikaze.', 'https://image.tmdb.org/t/p/w500/6e2YvN1tQK4xQHlmy7GJTuXOt2u.jpg', '2010-07-31', 14.07, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Adventure'),
(1415, 'Naruto Shippuden the Movie: Bonds', 'A mysterious group of ninjas makes a surprise attack on the Konohagakure, which takes great damage. The nightmare of another Shinobi World War could become a reality. Sasuke, who was still a missing nin from Konoha trying to kill his brother, Itachi, appears for the second time in front of Naruto at an unknown location to prevent it from happening.', 'https://image.tmdb.org/t/p/w500/bBqEiQbbfyt4MWR3NhDZMbS4Wp8.jpg', '2008-08-02', 7.32, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Fantasy'),
(1416, 'Naruto Shippuden the Movie: The Will of Fire', 'Ninjas with bloodline limits begin disappearing in all the countries and blame points toward the fire nation. By Tsunade\'s order, Kakashi is sacrificed to prevent an all out war. After inheriting charms left by Kakashi, Naruto fights through friends and foes to prevent his death while changing the minds of those who\'ve inherited the will of fire.', 'https://image.tmdb.org/t/p/w500/pZzdFmztwmg0FUOVCMa7vReHhQN.jpg', '2009-08-01', 13.01, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Action'),
(1417, 'Naruto Shippuden the Movie: Blood Prison', 'After his capture for attempted assassination of the Raikage, leader of Kumogakure, as well as killing JÅnin from Kirigakure and Iwagakure, Naruto is imprisoned in HÅzukijou: A criminal containment facility known as the Blood Prison. Mui, the castle master, uses the ultimate imprisonment technique to steal power from the prisoners, which is when Naruto notices his life has been targeted. Thus begins the battle to uncover the truth behind the mysterious murders and prove Naruto\'s innocence.', 'https://image.tmdb.org/t/p/w500/4WT7zYFpe0fsbg6TitppiHddWAh.jpg', '2011-07-30', 6.69, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Thriller'),
(1418, 'Naruto: The Lost Story - Mission: Protect the Waterfall Village!', 'Naruto and his friends must get back a jug of stolen holy water from a band of higher class ninjas.', 'https://image.tmdb.org/t/p/w500/mpFZiRihCsPDdZ1Ef69WIengKh2.jpg', '2003-12-20', 6.40, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1419, 'Naruto Shippuden: Sunny Side Battle', 'Sunny Side Battle! is an OVA that was released with Naruto Shippuden: Ultimate Ninja Storm Revolution. It features Itachi making breakfast for Sasuke in their old home.', 'https://image.tmdb.org/t/p/w500/rjtyKNkpXTLz8ukRR9x1AprdInn.jpg', '2013-10-06', 11.23, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Action'),
(1420, 'Naruto the Movie: Guardians of the Crescent Moon Kingdom', 'Naruto Uzumaki, Kakashi Hatake, Sakura Haruno, and Rock Lee are assigned to protect the prince of the Land of the Moon, Michiru, during his world trip; other escorts had been hired, but quit due to being treated poorly. The Land of the Moon is a very wealthy nation, so Michiru tends to buy whatever he wants, and has a very materialistic worldview. His Hikaru, also acts in much the same manner.', 'https://image.tmdb.org/t/p/w500/mmKiJ93x6uhTwJlrxCoY38R4qo6.jpg', '2006-08-05', 8.87, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Adventure'),
(1421, 'Naruto: The Cross Roads', 'Naruto: The Cross Roads (Za Kurosurozu) is the sixth Naruto OVA. It uses the same CGI graphics as Naruto: Ultimate Ninja Storm and was released during Naruto: Shippuden. This OVA premiered at the Jump Festa Anime Tour 2009. Between the Prologue - Land of Waves and Chunin Exams arcs, Team 7 is waiting for Kakashi, who is late again, to start a new mission (B-ranked as Sasuke states). The team sets off while Kakashi explains that Genmai from the Inaho Village is missing, who has vanished in the hills.', 'https://image.tmdb.org/t/p/w500/14fvXNxNDt0uecwMpLgCOiWlXWE.jpg', '2009-12-19', 10.32, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1422, 'The Last: Naruto the Movie', 'Two years after the events of the Fourth Great Ninja War, the moon that Hagoromo Otsutsuki created long ago to seal away the Gedo Statue begins to descend towards the world, threatening to become a meteor that would destroy everything on impact. Amidst this crisis, a direct descendant of Kaguya Otsutsuki named Toneri Otsutsuki attempts to kidnap Hinata Hyuga but ends up abducting her younger sister Hanabi. Naruto and his allies now mount a rescue mission before finding themselves embroiled in a final battle to decide the fate of everything.', 'https://image.tmdb.org/t/p/w500/bAQ8O5Uw6FedtlCbJTutenzPVKd.jpg', '2014-12-06', 11.28, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Action'),
(1423, 'Naruto x UT', 'Naruto x UT is the eighth Naruto OVA. Approximately 200,000 copies of this OVA were distributed by Uniqlo to promote a line of Naruto-themed shirts designed by Masashi Kishimoto in conjunction with Studio Pierrot. It shows the aftermath between a fight between Naruto and Sasuke and shows clips of their times together and the story so far.', 'https://image.tmdb.org/t/p/w500/5ds86rcR01tHvgsNimlQoIFFlqB.jpg', '2011-01-01', 12.77, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1424, 'Naruto Shippuuden OVAÂ -Â Uchiha Madara vs Senju Hashirama', 'Naruto ShippÅ«den Ultimate Ninja Storm Generations OVA Madara vs Hashirama is the tenth Naruto OVA. It is distributed as part of Naruto ShippÅ«den: Ultimate Ninja Storm Generations.', 'https://image.tmdb.org/t/p/w500/3AwkYyiwl02CMELo2oj88x2bEtu.jpg', '2012-02-23', 14.44, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1425, 'Live Spectacle NARUTO ~Song of the Akatsuki~', 'After parting with Sasuke at the Final Valley, Uzumaki Naruto has been away from the village of Konohagakure to further his training. Two and a half years later, he finally returns to the village and takes his mission in Team Kakashi, then he finds the clue on Orochimaru. Naruto leads the team and heads to the place where Orochimaru is in order to save his friend Sasuke. However, little does he know that \"Akatsuki\" is seeking after his life to acquire the Nine-Tailed sealed in his body.', 'https://image.tmdb.org/t/p/w500/nHaUUFFLESm5cRO6oD5NQ4nDQkW.jpg', '2021-01-07', 19.04, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'unknown'),
(1426, 'Naruto 20th Anniversary - Road of Naruto', 'Promotional video celebrating 20 years of the Naruto animation project.', 'https://image.tmdb.org/t/p/w500/fQdbaCovWOokxrE2qO6LiHZUB7H.jpg', '2022-10-02', 18.03, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1427, 'Kamiusagi Rope x Boruto: Naruto Next Generations', 'A 3-way collaboration between Kamiusagi Rope, Boruto: Naruto Next Generations, and TOHO Cinemas. The purpose is to promote a new TOHO theater opening up in Ueno on November 4, 2017. The collaboration video will also be available to view in TOHO Cinemas in Tokyo, Kanagawa, Chiba, and Saitama from Ocotober 21 - December 1.', 'https://image.tmdb.org/t/p/w500/6Y4u5yeuKFOqmD85A6V3RlSEB8e.jpg', '2017-10-14', 19.66, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1428, 'Naruto, the Genie, and the Three Wishes, Believe It!', 'Naruto discovers a genie\'s bottle while he and the gang are at a genin grill party. When everyone finds out about the genie\'s ability to grant wishes, the ultimate chase begins.', 'https://image.tmdb.org/t/p/w500/zuydzpfVgPDFZrBxauAUJMbBbXe.jpg', '2010-07-31', 15.97, '2025-04-14 20:34:21', '2025-04-14 20:34:21', 'Animation'),
(1429, 'One Piece: Episode of Skypiea', 'The Straw Hats embark on a dangerous trip to the sky where their destination comes straight out of a fairytale. The island of Skypiea and its grand city of gold await among the clouds, but a clash of winged clans and a man who calls himself God wonâ€™t make things easy! Only Luffy can resist this Godâ€™s mighty power and light the mysteries of the past.', 'https://image.tmdb.org/t/p/w500/whvgyEpPqvKXP0vZE4PMkoUmRqb.jpg', '2018-08-25', 14.69, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'TV Movie'),
(1430, 'Dream 9 Toriko x One Piece x Dragon Ball Z Super Collaboration Special!!', 'A two-part crossover special featuring characters from Dragon Ball Z, One Piece and Toriko.', 'https://image.tmdb.org/t/p/w500/1azUShBxKqHUUJf61BIpnJTtAWO.jpg', '2013-04-07', 13.71, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1431, 'One Piece: Adventure of Nebulandia', 'The Foxy Pirates challenge Luffyâ€™s crew in the New World, but the fun and games go belly-up when the Navyâ€™s most brilliant tactician steps in. Before the Straw Hats even know what hit them, they wind up on the island of Nebulandia, an infamous death trap for Devil Fruit users. Luffy must team up with his Davy Back nemesis for a harrowing rescue mission when Zoro, Sanji, and some Foxy Pirates are held hostage!', 'https://image.tmdb.org/t/p/w500/gpHuW2shQwknL5ZaEk3LE8bX1tL.jpg', '2015-12-20', 19.89, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1432, 'One Piece: Curse of the Sacred Sword', 'The Straw Hat Pirates landed at Asuka Island, home of the most valuable sword in the world: The Seven Star Sword. Which was said to curse anyone who takes it in possession. When they got back to the Going Merry, they discovered that Zoro is missing from his guard duty. Before they could plan out a search party to relocate him. Luffy and friends escape from the port as Marines were on their tail. They found a new place to dock, which is near a village. Whose job is to keep the Seven Star Sword sealed. Soon it was attacked by the Marines, and among them is Zoro. Luffy and the others don\'t know why he\'s helping out the Marines. But it all comes to conclusion when Luffy encounters Saga: Zoro\'s childhood friend from Swordsman training.', 'https://image.tmdb.org/t/p/w500/ivSa5qr5USM5sw9KpoM5ViIhJs0.jpg', '2004-03-06', 18.36, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1433, 'One Piece: Stampede', 'The world\'s boldest buccaneers set sail for the great Pirate Festival, where the Straw Hats join a mad-dash race to find Gol D. Roger\'s treasure. There\'s just one little problem: An old member of Roger\'s crew has a sinister score to settle.', 'https://image.tmdb.org/t/p/w500/lTmEC8wYMnivC4inWDthavlMkBS.jpg', '2019-01-03', 7.34, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1434, 'One Piece: Jango\'s Dance Carnival', 'The Straw Hat Pirates visit Mirrorball Island. Where a big dance carnival is being held. Jango the Hypnotist was there too, to show off his dance moves. Only when he was found by a group of Marines who were about to arrest him. But ended up chasing him throughout the island. Our heroes got involved when one of the Marines recognized Luffy from the wanted poster. And they end up getting chased as well. Soon Jango steals the spotlight of the dance carnival and uses his hypnosis on everyone on the island. And soon everyone including Jango, The StrawHat Pirates, and the marines are all dancing like there\'s no tomorrow.', 'https://image.tmdb.org/t/p/w500/s0veqgth8KG1h0Dr5an3NQdkqJD.jpg', '2001-03-03', 19.98, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Music'),
(1435, 'One Piece \"3D2Y\": Overcome Ace\'s Death! Luffy\'s Vow to his Friends', 'The special takes place during the two year before the Straw Hats reunite on Sabody.  Luffy is currently in Rusukaina training to get stronger to take on the New World. However the training  is interrupted when Hancock\'s sisters, Marigold and Sandersonia, are kidnapped by the Byrnndi World,  a pirate who was locked away on Level 6 of Impel Down but escaped during Luffy\'s invasion to save Ace,  in order to lure Hancock to him and use her as a hostage against the World Government due to her  Shichibukai status. Thus Luffy and Hancock head off to confront him and save Hancock\'s sisters.', 'https://image.tmdb.org/t/p/w500/caUI7YlhVXykFWQ7Ul7RQ2wQRpv.jpg', '2014-12-31', 18.51, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1436, 'One Piece Film: Z', 'Zephyr, now known as Z, rides the seas with only one goal: Destroy all pirates and their dreams at becoming King of Pirates. When Luffy and his crew encounter him at sea, not only are they utterly defeated by the man with an arm made of Seastone, Nami, Robin, and Chopper are turned 10 years younger due to Z\'s minion Ain. Luffy is so determined to win against him that he does not even notice Z\'s master plan that could sacrifice thousands of lives.', 'https://image.tmdb.org/t/p/w500/oP568qNH1LLEsoqGiZmf8deTOWc.jpg', '2012-12-15', 13.79, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1437, 'One Piece: Heart of Gold', 'A girl named Olga is pursued by both the World Government and a man named Mad Treasure, as she is the only one who knows the location of the Pure Gold, a substance that can buy the entire world. Olga ends up sailing with the Straw Hat Pirates, and they journey to find the Pure Gold on the lost island of Alchemi, which is located inside the stomach of a large angler fish named Bonbori.', 'https://image.tmdb.org/t/p/w500/e91hSNOwrV9FvC8LyaroK8dYTlZ.jpg', '2016-12-31', 16.68, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1438, 'One Piece 3D: Straw Hat Chase', 'One Piece 3D: Straw Hat Chase is the 11th One Piece film of the series, and is set before the time-skip. This is One Piece\'s first movie release to be in 3D CGI. The movie is also the first One Piece film since Movie 3 to be a double-feature. This time, the film was featured with \"Toriko 3D: Gourmet Adventure\", both being billed as the \"Jump Heroes Film\". The double-feature was released on March 19, 2011.', 'https://image.tmdb.org/t/p/w500/eYm3oEPiQJ9RV5QdyudwUplb9cD.jpg', '2011-03-19', 9.62, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1439, 'One Piece Film: GOLD', 'The glittering Gran Tesoro, a city of entertainment beyond the laws of the government, is a sanctuary for the worldâ€™s most infamous pirates, Marines, and filthy rich millionaires. Drawn by dreams of hitting the jackpot, Captain Luffy and his crew sail straight for the gold. But behind the gilded curtains lies a powerful king whose deep pockets and deeper ambitions spell disaster for the Straw Hats and the New World alike.', 'https://image.tmdb.org/t/p/w500/9PgiOFTLZXP7emlwcIt0yRasJ9h.jpg', '2016-07-23', 13.34, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1440, 'One Piece: Clockwork Island Adventure', 'Relaxing on a cozy beach, the Straw Hat Pirates are taking a rest from their quest. Right until Luffy noticed the Going Merry has been hijacked and sailed off from the beach. This leads them to search the ship and find the thief who took it from them. They ran into a duo named the Theif Brothers, who informed them that their ship was stolen by a group of pirates called the Trump Kyoudai. When they encountered the Trump Pirates, Nami ended up getting kidnapped as well as Luffy\'s hat. They tracked down the pirates to their base on Clockwork Island. Now Luffy, Zoro, Sanji, Usopp, and the Theif Brothers must reclaim the Going Merry, Save Nami, and get back Shank\'s straw hat.', 'https://image.tmdb.org/t/p/w500/yVr6EHUIrYpxRHACWkJoJTsFJX.jpg', '2001-03-03', 18.17, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1441, 'One Piece Film Red', 'Uta â€” the most beloved singer in the world. Her voice, which she sings with while concealing her true identity, has been described as â€œotherworldly.â€ She will appear in public for the first time at a live concert. As the venue fills with all kinds of Uta fans â€” excited pirates, the Navy watching closely, and the Straw Hats led by Luffy who simply came to enjoy her sonorous performance â€” the voice that the whole world has been waiting for is about to resound.', 'https://image.tmdb.org/t/p/w500/ogDXuVkO92GcETZfSofXXemw7gb.jpg', '2022-08-06', 14.93, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1442, 'One Piece: Baron Omatsuri and the Secret Island', 'The Straw Hats visit a recreational island, run by Baron Omatsuri, who asks them to complete a series of ordeals if they wish to stay on the island. Luffy accepts and the Straw Hats work together to complete them, but as the island\'s mysteries unfold, their lives and friendships are put to the test. It\'s up to Luffy to stop the Baron\'s plot and keep his crew together.', 'https://image.tmdb.org/t/p/w500/ueIR4LM4k8eKhSB8gGT9NMhCwGW.jpg', '2005-03-05', 11.84, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1443, 'One Piece: Episode of Chopper Plus: Bloom in the Winter, Miracle Cherry Blossom', 'When Nami falls ill, the Straw Hats seek medical care for her on Drum Island. There they meet reindeer doctor Tony Tony Chopper and the Wapol Pirates.', 'https://image.tmdb.org/t/p/w500/wMo8ujV0KATJhlm8jjNsIv6PrsI.jpg', '2008-03-01', 12.73, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1444, 'One Piece: Strong World Episode 0', 'The introductory chapter to the movie, Strong World, which depicts the events surrounding Gold Roger\'s execution.', 'https://image.tmdb.org/t/p/w500/5m0FhjQdWhBS3nkRFKIfkwFt1Zc.jpg', '2010-04-24', 8.75, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1445, 'One Piece Film: Strong World', '20 years after his escape from Impel Down, the legendary pirate Shiki, the Golden Lion, reappears causing massive upheaval to the Marines. During his long seclusion, he was able to come up with a scheme to bring the World Government to his knees. On his way to execute the plan, Shiki crosses paths with the Straw Hat Pirates and becomes so impressed with Nami\'s knowledge of meteorology that he abducts her to forcedly enlist her into his crew. Luffy and the gang end up on a strange land populated with monstrous beasts as they desperately search for Shiki and Nami.', 'https://image.tmdb.org/t/p/w500/gz8ZSM9WpG9M3JtGqRTvJbyFKnm.jpg', '2009-12-12', 10.20, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1446, 'One Piece: Dead End Adventure', 'Desperate for cash, the Straw Hat Pirates enter a secret race between pirate crews known as the Dead End Competition. There, they must battle against powerful people, including the bounty hunter who wants to kill Gasparde and a climatic battle with Marine-turned-pirate Captain Gasparde.', 'https://image.tmdb.org/t/p/w500/tEJBIHzaW1IoOVHtgblXy76kj4G.jpg', '2003-03-01', 17.01, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1447, 'One Piece: Episode of Luffy - Hand Island Adventure', 'As Luffy and the crew were attacked by several marine warships, they were forced to use a Coup de Burst to escape. Crash landing on an island, the crew decided to explore while some repairments are made. Upon meeting an wax artisan and learning the truth behind the island, Luffy offers his help.', 'https://image.tmdb.org/t/p/w500/29SOwiaxybMcSpY8N0rz7u5XGDf.jpg', '2012-12-15', 12.73, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Action'),
(1448, 'One Piece Special: Open Upon the Great Sea! A Father\'s Huge, HUGE Dream!', 'Bonnie & Max are crew members of Pirate Zap\'s ship. They\'re tired of the life they\'re in a want to escape. Only problem is they have no money. Three child hostages over heard their conversation and the eldest, Amanda knows where Bonnie & Max can get loaded. As her father was a pro treasure hunter who hid a treasure and made a deal that they can have it. Max & Bonnie agreed and sneaked away with the 3 kids. And spent one month on the small island on where the treasure is said to be. Luffy and his crew got involved with the conflict. And end up battling against the Bayan & Zap Pirates who both want the same thing. And Amanda is the key to locating the treasure. Will the treasure be claimed by the right people?', 'https://image.tmdb.org/t/p/w500/wa7I5E9PegOOMVWE0pPLtSAt42S.jpg', '2003-04-06', 13.66, '2025-04-14 20:34:29', '2025-04-14 20:34:29', 'Animation'),
(1449, 'None But the Brave', 'College hero Charles Stanton fails miserably as an insurance agent; so he becomes a lifeguard, saves an injured swimmer and is rewarded for his valor.', 'https://image.tmdb.org/t/p/w500/lBVG2ZI04C66hvdCoDjauquACEA.jpg', '1928-08-05', 12.78, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Comedy'),
(1450, 'The Blade Spares None', 'Ho Li-Chun, a pretty but ruthless swordswoman, and three challengers are participating in an open tournament at Prince Kuei\'s Palace. A knight, Chen Jo-Yu, is defeated in the tournament. He flees and later returns with knight Tang Ching-Yun who wields a strange sword. They get trapped but Ho deliberately sets both free after seeing Tang\'s weapon which she recognizes as the same weapon once used by Sun Tien-Chen, a foe of the Ho family. She decides to investigate. She finds out Prince Kuei actually is Sun, who killed the real prince years ago and assumed his identity. Ho joins forces with Chen and Tang. The trio slays Sun in a desperate confrontation at the palace.', 'https://image.tmdb.org/t/p/w500/qk9b4belX71BbShSlh1mu3xP93Q.jpg', '1971-04-30', 12.17, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Drama'),
(1451, 'None But the Lonely Heart', 'When an itinerant reluctantly returns home to help his sickly mother run her shop, they\'re both tempted to turn to crime to help make ends meet.', 'https://image.tmdb.org/t/p/w500/st37wKa1ZUbVSlKFI1fuUWb0rbi.jpg', '1944-10-17', 12.17, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Drama'),
(1452, 'The Heaven None Missed 2', 'Pras felt something is wrong with his first wife, Arini. Arini asked Pras to fight for his second wife Meirose to return Indonesia and live together.', 'https://image.tmdb.org/t/p/w500/ifugXbVH4OGhc1QQuGIh4QITdsU.jpg', '2017-02-09', 12.78, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Drama'),
(1453, 'The Heaven None Missed', 'Pras and Arini\'s love was destroyed in Arini\'s eyes when he chose to marry Meirose secretly. Their ideal marriage collapsed instantly.', 'https://image.tmdb.org/t/p/w500/cxYCqMGX3vlBfFNO5RrCUZ2LONS.jpg', '2015-07-15', 15.26, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Drama'),
(1454, 'The Nonentity', 'Each evening, four men â€“ a doctor, a journalist, a professor and a merchant â€“ meet up in a deserted bar to play cards.  As they play, the barâ€™s owner, her downtrodden barman (nicknamed â€œle paltoquetâ€) and a strange woman in white watch from a distance.  One night, the card game is disturbed when a police inspector suddenly appears and declares that a dead body has been found nearby.  Certain that one of the four men is the murderer, the inspector starts his investigation.  All the evidence suggests that the doctor did the deed, but we soon learn that nothing is quite what it seemsâ€¦', 'https://image.tmdb.org/t/p/w500/k5MgS8Ryjq9Sm4BvqyIptWbQzRr.jpg', '1986-08-13', 17.48, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Crime'),
(1455, 'The Heaven None Missed 3', 'Meirose strives to create heaven in her family, with her husband and their two children. One day, Ray, a man from her past, returns and wants to build his lost paradise with Meirose and Akbar.', 'https://image.tmdb.org/t/p/w500/8eyygpvyWwFRhh5y8f6A8HKOyQe.jpg', '2021-04-16', 12.58, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Drama'),
(1456, 'The Book by Zhama Yuko. Rare Species of Non-Existent Animals', ' ', 'https://via.placeholder.com/500x750?text=No+Image', '2024-03-15', 7.15, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Animation'),
(1458, 'The Nonexistent Knight', 'Agilulfo is a righteous, perfectionist, faithful and pious knight with only one shortcoming: he doesn\'t exist. Inside his empty armor is an echoing voice that reverberates through the metal. Nevertheless, he serves the army of a Christian king out of goodwill and faith in the holy cause.', 'https://image.tmdb.org/t/p/w500/wU4pP8AS4rrzZmD68yjzmgGBaxV.jpg', '1969-12-30', 15.84, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Animation');
INSERT INTO `movies` (`id`, `title`, `description`, `poster_path`, `release_date`, `price`, `created_at`, `updated_at`, `category`) VALUES
(1459, 'Pure Air of the Mountain: For All and None', 'In the heart of the mountain, an elusive and invisible observer witnesses an infamous spectacle. His voice comments on the sequence of events in the words of Nietzsche. In this splendid mountain landscape, a couple appears. Spenta, the man, and Angra, the woman, climb a steep peak. They wear similar clothes, their resemblance is amazing, their relationship is strange. To outsmart boredom Angra drags Spenta, initially unenthusiastic, into a game that he eventually gives in. From the top, the couple watches a marathon event that takes place in the valley. Angra, who is looking for an object of entertainment, has her sights set on a woman running through the crowd. Possessed, she courted the unknown and obtained her favors. She then manages to drag Spenta into her game. In this game, there will be no winner.', 'https://image.tmdb.org/t/p/w500/4yM6RHRJwpPfM5iwPHYXNyq3eox.jpg', '2023-11-16', 11.41, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Comedy'),
(1460, 'Arthur Miller, Elia Kazan and the Blacklist: None Without Sin', 'Director Elia Kazan and playwright Arthur Miller were once best friends and professional colleagues, to most that knew them then in both capacities as soul mates. Their politics were similar which was reflected in their work. Kazan was a Communist Party member for a few years in the mid-1930\'s, but Miller never officially joined the party ranks. Their relationship changed in the early 1950\'s when Kazan was subpoenaed to testify in front of the House Un-American Activities Committee where he named names of  Communist Party members past and present.', 'https://image.tmdb.org/t/p/w500/p8T9HKP0Sf4t6IUoqihAXnPOpYp.jpg', '2003-09-03', 19.94, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'History'),
(1461, 'Norn9: Norn + Nonette - The Stage', 'Norn9: Norn + Nonette adaptation', 'https://image.tmdb.org/t/p/w500/uRdNqMuh5kzzYWJfHcKfmbFIcP6.jpg', '2018-01-01', 10.23, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'unknown'),
(1462, 'There were none left from the Tata sisters', 'One winter afternoon, two siblings visit the grave of their beloved grandmother for the first time. In front of the view of the tomb and the abrupt contact with the loss, the siblings discover, in a snowy landscape, the paradoxical ways in which mourning can be expressed.', 'https://image.tmdb.org/t/p/w500/rbc8NiAl8aib1sI8BDof8fSShMT.jpg', '2022-05-22', 19.79, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Drama'),
(1463, 'None of the World\'s Futures', 'Looking back at footage of Venice Biennale 2011, The Artist remembers the optimistic feelings felt at the time, the projected careers, the romantic setting and how art meant something. The Finnish pavilion was closed when the footage was shot because of a fallen tree. Was it a sign? The sinking city echoes The Artist\'s current sense of resignation. The piece shifts from video footage into cartoons with speech bubbles, perhaps in an effort to reclaim the voiceover from a romanticising of ennui that seemed to be setting in. Is this a new beginning? Liberated from its ambitions for an illustrious career, art has now become a more metaphysical means of survival.', 'https://image.tmdb.org/t/p/w500/omnL8OKb6mNUSLVcSCpHzH5RgRG.jpg', '2016-01-01', 17.63, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Documentary'),
(1464, 'To the North for Nonexistence', 'The SÃ¡mi people are the land of accumulation of time and the indigenous peoples of the polar regions of Northern Europe, which have been geographically isolated for a long time due to severe weather conditions. Nowadays, the traditional way of life of the SÃ¡mi people living in minority groups and their own identity inevitably arouse conflict with modern systems. To Anita Gimvall who is a SÃ¡mi tribe who has lived a lifetime in Lapland, it shows a cross-section of the recent arson incident in a traditional house. To the North for Nonexistence traces out a conflict and alienation at the ambiguous border between past tradition and modern life, settlement and deportation, thought and sharing, and stories of blurred boundaries and backgrounds inside and outside.', 'https://image.tmdb.org/t/p/w500/uQxix4lOsxnKx00ysczaxd4sL3k.jpg', '2019-01-01', 15.03, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'unknown'),
(1465, 'The Nonexistence', 'A thirsty vampire goes into the night searching for blood. However, his encounter with a ghostly presence in a subway wagon will take him on a strange sensory journey, during which he will adopt different forms, as well as ways to exist through and despite others.', 'https://image.tmdb.org/t/p/w500/v4xvIqgZ20XgqGWQhHmVHkqH2S8.jpg', '2024-03-07', 10.58, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'Horror'),
(1466, 'None of the Above', 'Five immigrant women from four different countries: Brazil, Romania, Italy, and Turkey navigate expectations, stereotypes, and cultural shocks in the United States, all while trying to hold on to their own identity. Through a series of sketches and a few short scenes based on real conversations, the women poke fun at peopleâ€™s preconceived notions about their cultures, but also raise important questions regarding their status in the US.', 'https://via.placeholder.com/500x750?text=No+Image', NULL, 12.77, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'unknown'),
(1468, 'None For The Road', 'The dangers of drinking and driving are illustrated in this tale of three friends - one who drinks a lot, one who drinks a little and one who doesn\'t drink at all - and what happens to them on a weekend evening.', 'https://image.tmdb.org/t/p/w500/eN9XiOkhLshMYopQ7041H30CeeV.jpg', '1957-01-01', 17.94, '2025-04-14 20:36:41', '2025-04-14 20:36:41', 'unknown');
